-- Poems batch 275
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f5ab6aad-e257-41b1-ab6a-e36ac686b92d','邵武泰寧途間一路海棠','陳普','宋','宋诗','song-poetry','','[]','萬騎連接出襄國，諸姨撩亂上驪山。',32,'全唐诗/poet.song.243000.json','["萬騎連接出襄國，諸姨撩亂上驪山。", "道人不識紅粧面，何事扶筇過此山。"]'),
('3cf74647-343c-4fed-9747-07d4840f4563','武夷一曲','陳普','宋','宋诗','song-poetry','','[]','虹橋一斷幾千齡，親手文公再造成。',32,'全唐诗/poet.song.243000.json','["虹橋一斷幾千齡，親手文公再造成。", "何事遊人尚迷路，亂尋無楫渡船撐。"]'),
('05af74b0-ac88-46b8-9d3b-5a4f1c962ed0','玉女峰','陳普','宋','宋诗','song-poetry','','[]','暮暮朝朝此水頭，却無雨怨與雲愁。',32,'全唐诗/poet.song.243000.json','["暮暮朝朝此水頭，却無雨怨與雲愁。", "我儀何事堂堂去，極目天涯雙鬢秋。"]'),
('c6903d45-9102-4658-aec6-0e482fb679fd','大王峰','陳普','宋','宋诗','song-poetry','','[]','統攝群峰占水湄，長如翼德斷橋時。',32,'全唐诗/poet.song.243000.json','["統攝群峰占水湄，長如翼德斷橋時。", "惡聲聊斷仙靈耳，赤幘空汗百世師。"]'),
('dbc1f682-7387-48de-849e-44203bb6cd31','隠屏','陳普','宋','宋诗','song-poetry','','[]','排雲觝雨立虛空，端正方嚴萬壑中。',32,'全唐诗/poet.song.243000.json','["排雲觝雨立虛空，端正方嚴萬壑中。", "好去明堂充宁倚，不應留此伴仙翁。"]'),
('41af6ccb-ed09-4602-9438-b2a1144f53a7','仙掌','陳普','宋','宋诗','song-poetry','','[]','丹崖翠壁盡仙梯，不用囊中大藥資。',32,'全唐诗/poet.song.243000.json','["丹崖翠壁盡仙梯，不用囊中大藥資。", "成道無過是無欲，仙靈分曉示諸斯。"]'),
('4ea3a379-f605-41ed-83ae-f27a9b33a791','天柱峰','陳普','宋','宋诗','song-poetry','','[]','撐天拄地氣何雄，絕似多愁杞國翁。',32,'全唐诗/poet.song.243000.json','["撐天拄地氣何雄，絕似多愁杞國翁。", "五曲年來添個伴，從今不復患共工。"]'),
('66c3cc6d-87f4-477f-aa93-5f1cb7794b75','一線天','陳普','宋','宋诗','song-poetry','','[]','天真道妙本無多，只費挨攤與洗磨。',32,'全唐诗/poet.song.243000.json','["天真道妙本無多，只費挨攤與洗磨。", "不見昭昭端的處，分明全體是如何。"]'),
('4c7f2aed-9783-4929-8eff-a0d212e1c51b','石堂  其一','陳普','宋','宋诗','song-poetry','','[]','仙佛人言是一家，好分半席共煙霞。',32,'全唐诗/poet.song.243000.json','["仙佛人言是一家，好分半席共煙霞。", "廓清摧陷儒家事，不謂青山識正邪。"]'),
('24af08a8-7878-491b-868c-412c0fde208f','石堂  其二','陳普','宋','宋诗','song-poetry','','[]','天威如許敢爭雄，重遣山靈費一峰。',32,'全唐诗/poet.song.243000.json','["天威如許敢爭雄，重遣山靈費一峰。", "不共那邊如水火，未應抵死不相容。"]'),
('cb945065-dcf7-4c3b-89d7-f545995cf109','石堂  其三','陳普','宋','宋诗','song-poetry','','[]','蕭蕭五曲片茆茨，環合群峰共護持。',32,'全唐诗/poet.song.243000.json','["蕭蕭五曲片茆茨，環合群峰共護持。", "天下七情誰中節，武夷山石百王師。"]'),
('b97710e8-1d74-42a2-8e7f-bbc53834816e','石堂  其四','陳普','宋','宋诗','song-poetry','','[]','聞言驚喜是家山，朅蹙來茲遂一攀。',32,'全唐诗/poet.song.243000.json','["聞言驚喜是家山，朅蹙來茲遂一攀。", "何但名稱偶相似，宛然天壁鎖雲關。"]'),
('bf4b6549-1392-4cef-aca2-ab3b3c019541','石堂  其五','陳普','宋','宋诗','song-poetry','','[]','新豐雞犬路終迷，廬下濂溪非故溪。',32,'全唐诗/poet.song.243000.json','["新豐雞犬路終迷，廬下濂溪非故溪。", "造物留人殊過當，終當結屋此雲栖。"]'),
('14acba78-6199-42b0-8d8c-0b86c7d29215','伯循和石堂後二首復依韻  其一','陳普','宋','宋诗','song-poetry','','[]','晉士當年一峴山，高風千古邈難攀。',32,'全唐诗/poet.song.243000.json','["晉士當年一峴山，高風千古邈難攀。", "浮嵐煖翠依然在，不入人間大夢關。"]'),
('cdb55b09-9d79-4998-826f-5ffd497e9867','伯循和石堂後二首復依韻  其二','陳普','宋','宋诗','song-poetry','','[]','櫂歌一唱醒群迷，先有胸中九曲溪。',32,'全唐诗/poet.song.243000.json','["櫂歌一唱醒群迷，先有胸中九曲溪。", "仁智之真常瑩徹，過門不入亦山栖。"]'),
('0aa15654-86cb-496d-9cd5-6503bea927ba','赤壁賦中四句 耳得之而爲聲','陳普','宋','宋诗','song-poetry','','[]','司聰坎體本來清，舉世都將貯笛箏。',32,'全唐诗/poet.song.243000.json','["司聰坎體本來清，舉世都將貯笛箏。", "飽聽翛翛北窗吹，人間能有幾長庚。"]'),
('9b713909-8c55-4955-ad4d-85cb22548a4e','赤壁賦中四句 目遇之而成色','陳普','宋','宋诗','song-poetry','','[]','人間何處看真色，午夜天心月滿時。',32,'全唐诗/poet.song.243000.json','["人間何處看真色，午夜天心月滿時。", "無限凡夫空肉眼，凝眸决眥望西施。"]'),
('c977c845-ea66-4ac7-a86f-75ed7cc8b38b','赤壁賦中四句 取之無禁','陳普','宋','宋诗','song-poetry','','[]','竹聲梅影芰荷香，滿檐連車不是贜。',32,'全唐诗/poet.song.243000.json','["竹聲梅影芰荷香，滿檐連車不是贜。", "無奈浮雲并糞土，百年瞬息萬人忙。"]'),
('cce63f82-ab3f-42e5-8dad-c3eb1cf2fc11','赤壁賦中四句 用之不竭','陳普','宋','宋诗','song-poetry','','[]','白璧黄金殺五侯，只堪揮斥不堪留。',32,'全唐诗/poet.song.243000.json','["白璧黄金殺五侯，只堪揮斥不堪留。", "柳風梧月窗前草，此興江河日夜流。"]'),
('70457e87-0edd-49ee-9699-e19603edd090','歸鳥','陳普','宋','宋诗','song-poetry','','[]','紫山青嶂盡如家，負日衝烟復带霞。',32,'全唐诗/poet.song.243000.json','["紫山青嶂盡如家，負日衝烟復带霞。", "今古乾坤秋一幅，幾番歸鳥與栖鴉。"]'),
('f55e9316-2e7c-4f7f-b378-6624c6347aa6','困王孫','陳普','宋','宋诗','song-poetry','','[]','養生喪死婦女手，受氣成形酒色胎。',32,'全唐诗/poet.song.243000.json','["養生喪死婦女手，受氣成形酒色胎。", "牧馬夜歸眠馬下，夢魂猶遶舊樓臺。"]'),
('e887f8d3-f601-4fe6-85b0-90350bbb019b','不解算  其一','陳普','宋','宋诗','song-poetry','','[]','孔桑祗是穢塵編，劉晏空誇馬上鞭。',32,'全唐诗/poet.song.243000.json','["孔桑祗是穢塵編，劉晏空誇馬上鞭。", "六合分明長策裏，不知劉項入關年。"]'),
('e1383e40-e10e-4d34-96e8-0f9714326664','不解算  其二','陳普','宋','宋诗','song-poetry','','[]','算來未必得盧梟，不算其如四壁蕭。',32,'全唐诗/poet.song.243000.json','["算來未必得盧梟，不算其如四壁蕭。", "大道廣居天與伍，肯將前箸亂簞瓢。"]'),
('c0a0bb77-3922-4814-a1e9-84aad3ccb42b','不解算  其三','陳普','宋','宋诗','song-poetry','','[]','管晏商斯幾揣摩，盡誇掌上有山河。',32,'全唐诗/poet.song.243000.json','["管晏商斯幾揣摩，盡誇掌上有山河。", "當身成就憑君問，孰與顔曾孔孟多。"]'),
('98878ba5-54de-4f58-853d-d39277b0d16d','不解算  其四','陳普','宋','宋诗','song-poetry','','[]','漢初帷幄有真儒，五百餘人轍予盧。',32,'全唐诗/poet.song.243000.json','["漢初帷幄有真儒，五百餘人轍予盧。", "三十六宮來往處，子房終得邵堯夫。"]'),
('1f0cd0e5-f5f0-480f-af5d-4fff20b86097','七月六日夜雨','陳普','宋','宋诗','song-poetry','','[]','蒼生一一共胞胎，日夜無端心上來。',32,'全唐诗/poet.song.243000.json','["蒼生一一共胞胎，日夜無端心上來。", "半月驕陽四更雨，豳風夏校夢初回。"]'),
('273c0315-a3ea-4059-ac2c-5b3699e80439','七夕  其一','陳普','宋','宋诗','song-poetry','','[]','玉果金盤開九州，人間無處匿蛛蟊。',32,'全唐诗/poet.song.243000.json','["玉果金盤開九州，人間無處匿蛛蟊。", "天孫今夜鵲橋畔，百億化身難得周。"]'),
('dad6d8b3-cd20-4f14-b2cb-58f6a3f63c6f','七夕  其二','陳普','宋','宋诗','song-poetry','','[]','但把凡身小品論，不須榻頞問星辰。',32,'全唐诗/poet.song.243000.json','["但把凡身小品論，不須榻頞問星辰。", "女郎戀別淚如雨，遑托金針度與人。"]'),
('9e0ab2b0-1712-4cdd-830e-40ad159c7433','七夕  其三','陳普','宋','宋诗','song-poetry','','[]','欲理銀河一葉舟，不知滿架架蒙鳩。',32,'全唐诗/poet.song.243000.json','["欲理銀河一葉舟，不知滿架架蒙鳩。", "漢陰抱甕蒼顔叟，孤負今朝乞巧樓。"]'),
('f7b42eb3-606c-414d-9bfc-b56c6922a5b7','七夕  其四','陳普','宋','宋诗','song-poetry','','[]','木牛流馬無人會，元是自家心孔開。',32,'全唐诗/poet.song.243000.json','["木牛流馬無人會，元是自家心孔開。", "却恐如簧讒佞口，曾問天孫乞巧來。"]'),
('1e004bc9-2e58-4ff1-88cd-ceeb659b9e55','七夕  其五','陳普','宋','宋诗','song-poetry','','[]','織女牽牛不隔河，儼然天娣與相摩。',32,'全唐诗/poet.song.243000.json','["織女牽牛不隔河，儼然天娣與相摩。", "道心萬載如寒水，肯爲河東起浪波。"]'),
('9b79630c-87f0-4714-896a-a9d14fac035b','七夕後一日  其一','陳普','宋','宋诗','song-poetry','','[]','世間萬事但隨身，不費將迎是聖人。',32,'全唐诗/poet.song.243000.json','["世間萬事但隨身，不費將迎是聖人。", "雨暗雲昏殷作夜，天青水碧在今晨。"]'),
('fd610183-151e-4751-8709-c351583f033b','七夕後一日  其二','陳普','宋','宋诗','song-poetry','','[]','明朝來歲總過去，密意深情幾度春。',32,'全唐诗/poet.song.243000.json','["明朝來歲總過去，密意深情幾度春。", "此是吾徒塵垢事，敢將上下位星辰。"]'),
('18a12507-16f6-4415-b2ff-f11d57247bd5','中秋近願晴  其一','陳普','宋','宋诗','song-poetry','','[]','秋天連夕卷烟雲，似爲蓬蒿有滯人。',32,'全唐诗/poet.song.243000.json','["秋天連夕卷烟雲，似爲蓬蒿有滯人。", "駟馬高車無夢想，中秋但借一冰輪。"]'),
('6d3bf3a5-dc15-4563-bf97-3dba639268c5','中秋近願晴  其二','陳普','宋','宋诗','song-poetry','','[]','借得冰輪不敢私，幾多人要露肝脾。',32,'全唐诗/poet.song.243000.json','["借得冰輪不敢私，幾多人要露肝脾。", "浮雲不用欺天下，須信人間有伯夷。"]'),
('fc94ab0e-63d2-4fd9-970d-4615e1d3607f','中秋近願晴  其三','陳普','宋','宋诗','song-poetry','','[]','浩蕩無邊及物心，孔顔堯舜共弘深。',32,'全唐诗/poet.song.243000.json','["浩蕩無邊及物心，孔顔堯舜共弘深。", "柴荆一壑蒼苔合，惟幸寒蟾夜夜臨。"]'),
('45a6142c-480c-4998-acbb-2a899a9257eb','中秋近願晴  其四','陳普','宋','宋诗','song-poetry','','[]','生如螻蟻事如麻，有菜無鹽是幾家。',32,'全唐诗/poet.song.243000.json','["生如螻蟻事如麻，有菜無鹽是幾家。", "無限容光通照處，良晨莫遣片雲遮。"]'),
('6719b0ea-aa2d-4cb4-bd86-084d6af966e6','中秋近願晴  其五','陳普','宋','宋诗','song-poetry','','[]','春風秋月久交游，少壯論心今白頭。',32,'全唐诗/poet.song.243000.json','["春風秋月久交游，少壯論心今白頭。", "二子倘無相棄絕，從今但乞十中秋。"]'),
('43a56680-7dde-4d6c-9666-2cebeadec3f2','願月得雨兼旬秋晹人望已切再和前韻  其一','陳普','宋','宋诗','song-poetry','','[]','踰浹秋晹已望雲，芭蕉一夜慰愁人。',32,'全唐诗/poet.song.243000.json','["踰浹秋晹已望雲，芭蕉一夜慰愁人。", "陰陽各有時中處，不可相無似兩輪。"]'),
('a7038549-28b8-4acd-8f93-6fb5a9826d32','願月得雨兼旬秋晹人望已切再和前韻  其二','陳普','宋','宋诗','song-poetry','','[]','雨我公田及我私，幾多風月入肝脾。',32,'全唐诗/poet.song.243000.json','["雨我公田及我私，幾多風月入肝脾。", "天心亦似堯心細，一日之中有隩夷。"]'),
('9489e13d-bee6-48cb-89a2-50c5cf11d6b6','願月得雨兼旬秋晹人望已切再和前韻  其三','陳普','宋','宋诗','song-poetry','','[]','時雨光風總是吟，憂歡元不繫晴陰。',32,'全唐诗/poet.song.243000.json','["時雨光風總是吟，憂歡元不繫晴陰。", "醍醐未用踰玄酒，中節何須論淺深。"]'),
('0c436d52-5563-4e19-9bda-afa14165ca25','願月得雨兼旬秋晹人望已切再和前韻  其四','陳普','宋','宋诗','song-poetry','','[]','須識光風霽月心，愛君憂國慮民深。',32,'全唐诗/poet.song.243000.json','["須識光風霽月心，愛君憂國慮民深。", "江南一夜千倉廩，再拜雙眸重照臨。"]'),
('2759b4ac-0c0d-4d45-90e2-c02c1749b7bd','願月得雨兼旬秋晹人望已切再和前韻  其五','陳普','宋','宋诗','song-poetry','','[]','播穀栽桑復執麻，全憑雨露作人家。',32,'全唐诗/poet.song.243000.json','["播穀栽桑復執麻，全憑雨露作人家。", "世間惟有心須霽，一片浮雲不可遮。"]'),
('3b6a93f9-e43a-4c28-9a7d-dff2097dba94','願月得雨兼旬秋晹人望已切再和前韻  其六','陳普','宋','宋诗','song-poetry','','[]','得意如心即勝遊，不妨對雨作遨頭。',32,'全唐诗/poet.song.243000.json','["得意如心即勝遊，不妨對雨作遨頭。", "窮櫩豈暇賢明月，舉室寒衾喜有秋。"]'),
('07e7f682-db58-4caf-9025-7b191260d8cc','戲題趙畔道寓居壁間','陳普','宋','宋诗','song-poetry','','[]','疏髯荆楚青油客，踏著天根息此堂。',32,'全唐诗/poet.song.243000.json','["疏髯荆楚青油客，踏著天根息此堂。", "惹得深山狂簡子，年年來此道先生。"]'),
('017f3c7a-4183-408f-b0ec-0513e85fc5aa','屢省乃成  其一','陳普','宋','宋诗','song-poetry','','[]','務本工夫在日新，悠悠莫自老青春。',32,'全唐诗/poet.song.243000.json','["務本工夫在日新，悠悠莫自老青春。", "課功覈實惟時敏，德業何難輩古人。"]'),
('4e9a78a3-a1a6-4b21-bc57-9da8edc1c1b1','屢省乃成  其二','陳普','宋','宋诗','song-poetry','','[]','詩書總學本無難，年少心身莫暫閒。',32,'全唐诗/poet.song.243000.json','["詩書總學本無難，年少心身莫暫閒。", "尺寸之功當記取，將來百仞作高山。"]'),
('8f11d720-9599-4ffd-99df-b7915f802042','偶占','陳普','宋','宋诗','song-poetry','','[]','水邊側耳翠萄葉，陂下銷魂金步摇。',32,'全唐诗/poet.song.243000.json','["水邊側耳翠萄葉，陂下銷魂金步摇。", "何以潯陽北窗下，白雲伴宿聽翛翛。"]'),
