('c1ef4edd-68c6-4dfc-b5a4-d7698b6d87b8','喜雨示兒姪  其三','丘葵','宋','宋诗','song-poetry','','[]','維天降靈雨，豈不雨石田。',24,'全唐诗/poet.song.244000.json','["維天降靈雨，豈不雨石田。", "我自磽且确，枯悴莫怨天。"]'),
('79c3605b-480c-45df-bc8d-ca088161d49c','喜雨示兒姪  其四','丘葵','宋','宋诗','song-poetry','','[]','維天降靈雨，而或惰不耛。',24,'全唐诗/poet.song.244000.json','["維天降靈雨，而或惰不耛。", "他時無斂穧，誰憐汝啼饑。"]'),
('5add2487-7c56-4244-a60a-4831da9e98ce','蓮生  其一','丘葵','宋','宋诗','song-poetry','','[]','蓮生汙泥中，其葉何青青。',24,'全唐诗/poet.song.244000.json','["蓮生汙泥中，其葉何青青。", "人生有恒性，云胡蕩於情。"]'),
('7f9e8132-759f-4550-aae6-f85ed874a01f','蓮生  其二','丘葵','宋','宋诗','song-poetry','','[]','蓮生汙泥中，其葉何郁郁。',24,'全唐诗/poet.song.244000.json','["蓮生汙泥中，其葉何郁郁。", "人生有恒性，云胡蔽於欲。"]'),
('da0e01f4-354b-41e2-bd36-d714c27fea34','蓮生  其三','丘葵','宋','宋诗','song-poetry','','[]','蓮生汙泥中，其實何戢戢。',24,'全唐诗/poet.song.244000.json','["蓮生汙泥中，其實何戢戢。", "人生有恒性，云胡狃於習。"]'),
('f6869cc3-122b-4b38-b3e6-0646830a0658','石榴花  其一','丘葵','宋','宋诗','song-poetry','','[]','英英石榴花，不火而自晰。',36,'全唐诗/poet.song.244000.json','["英英石榴花，不火而自晰。", "凡今之人兮，誰不附炎熱。", "百鬼瞰高明，丹朱易傾跌。"]'),
('d7c5c95c-dba9-4f4c-b396-eeb91f7f7fa0','石榴花  其二','丘葵','宋','宋诗','song-poetry','','[]','英英石榴花，不朱而自赤。',36,'全唐诗/poet.song.244000.json','["英英石榴花，不朱而自赤。", "凡今之人兮，誰不悅媚色。", "脂水漲渭流，妍姿竟傾國。"]'),
('758ef3be-464c-4a8f-bd3b-bd2fed56cb85','庚辰歲寓開元東羅漢閣  其一','丘葵','宋','宋诗','song-poetry','','[]','有美者傑閣，凌然跨虛空。',36,'全唐诗/poet.song.244000.json','["有美者傑閣，凌然跨虛空。", "有覺者彼岸，廓然大圓通。", "而我獨蠢蠢，於何而適從。"]'),
('e4328119-c36d-4eb7-b529-7d7076e4d5f2','庚辰歲寓開元東羅漢閣  其二','丘葵','宋','宋诗','song-poetry','','[]','有崷者浮圖，屹其插穹昊。',36,'全唐诗/poet.song.244000.json','["有崷者浮圖，屹其插穹昊。", "有墳者古道，凄其鞠成草。", "而我獨兢兢，於焉以終老。"]'),
('c1e54a2c-8cf8-44fd-8ea0-7b601d0614a7','獨步芝山','丘葵','宋','宋诗','song-poetry','','[]','平生獨往願，頗得山林趣。',36,'全唐诗/poet.song.244000.json','["平生獨往願，頗得山林趣。", "輕陰春漠漠，淡日隨行屨。", "猶嫌影趁人，特入深深處。"]'),
('acf83f19-f692-4893-b183-75f7833dcc5c','溪橋看月','丘葵','宋','宋诗','song-poetry','','[]','當空一明鏡，圓圓水中見。',36,'全唐诗/poet.song.244000.json','["當空一明鏡，圓圓水中見。", "常恨溪頭風，吹來皺水面。", "水面皺猶可，月碎成萬片。"]'),
('852f8f01-59ff-44e7-b2df-b951c12c2d1d','義方堂瞻先賢遺像  其一','丘葵','宋','宋诗','song-poetry','','[]','龍龜不再出，誰能探真精。',36,'全唐诗/poet.song.244000.json','["龍龜不再出，誰能探真精。", "圖書天所付，手授之二程。", "欲知千載意，窗外草青青。"]'),
('51fb1a36-1fbc-44b5-83a6-64ca3101f2b7','義方堂瞻先賢遺像  其二','丘葵','宋','宋诗','song-poetry','','[]','三十六宮中，手探足還躡。',36,'全唐诗/poet.song.244000.json','["三十六宮中，手探足還躡。", "一元十二會，理亂在目睫。", "我欲從先生，□□□□□。"]'),
('bbe6a9d4-3bac-49a5-b7f2-385699faf444','義方堂瞻先賢遺像  其三','丘葵','宋','宋诗','song-poetry','','[]','性命同一原，誰能發其奧。',36,'全唐诗/poet.song.244000.json','["性命同一原，誰能發其奧。", "茫茫太虛中，指出天與道。", "精思與力踐，千古爲獨到。"]'),
('f4f07946-ce95-4573-9329-c4fdb7c4779f','義方堂瞻先賢遺像  其四','丘葵','宋','宋诗','song-poetry','','[]','石井初筮時，已將教爲政。',36,'全唐诗/poet.song.244000.json','["石井初筮時，已將教爲政。", "真成叔梁紇，有子爲孔聖。", "至今鼇山下，過者莫不敬。"]'),
('b2a836b6-7b2c-41a7-bf1a-2db3f939d94c','義方堂瞻先賢遺像  其五','丘葵','宋','宋诗','song-poetry','','[]','六經重刊定，炳炳如日月。',36,'全唐诗/poet.song.244000.json','["六經重刊定，炳炳如日月。", "毫分而縷析，反約以詳說。", "千載開我人，遺書□□□。"]'),
('173f9db7-4dfe-4b4d-9e6d-6a1a992834ea','義方堂瞻先賢遺像  其六','丘葵','宋','宋诗','song-poetry','','[]','炎炎太平翁，誰敢觸其諱。',36,'全唐诗/poet.song.244000.json','["炎炎太平翁，誰敢觸其諱。", "乞梟之藁街，公乃明大義。", "至今讀諫疏，凜凜有生氣。"]'),
('3b11c289-12d4-4197-b1f0-c0ef0b55c965','龍湖歸','丘葵','宋','宋诗','song-poetry','','[]','策蹇下平崗，掛帆渡安流。',84,'全唐诗/poet.song.244000.json','["策蹇下平崗，掛帆渡安流。", "平生不行險，間道旋故丘。", "高堂有鶴髮，安敢事遠遊。", "負米雖不多，過冬亦稍優。", "所愧無甘旨，一飽良易謀。", "兢兢保遺體，無遺慈顔憂。", "讀書茅簷下，庶幾少愆尤。"]'),
('063d1ef1-0ecd-41be-97df-82e85873d0a3','夜坐讀書','丘葵','宋','宋诗','song-poetry','','[]','茅簷晚來雨，東風忽吹晴。',84,'全唐诗/poet.song.244000.json','["茅簷晚來雨，東風忽吹晴。", "不暖亦不寒，夜氣覺自清。", "書生澹無事，復戀舊短檠。", "開卷見聖賢，愧我猶編氓。", "便思澡塵慮，肅然奉天明。", "出門視斗極，敬心由之生。", "姿年捨我去，老學何由成。"]'),
('8409afc1-8b26-48ef-a892-bb74934ed65b','風雨中與呂之壽讀文公詩傳','丘葵','宋','宋诗','song-poetry','','[]','冷冷葉上風，瑟瑟簷頭雨。',72,'全唐诗/poet.song.244000.json','["冷冷葉上風，瑟瑟簷頭雨。", "天分本無私，人性皆相似。", "譬之入山林，斧斤隨所取。", "姿年捨我去，初心日以負。", "勗君歲寒心，保此棟梁具。", "聖域廓悠悠，修途未容駐。"]'),
('e2830f9d-2d51-4308-bf9b-b38c9d634b94','跋巨然曉意圖','丘葵','宋','宋诗','song-poetry','','[]','秋曙已生白，朝暾尚潜紅。',72,'全唐诗/poet.song.244000.json','["秋曙已生白，朝暾尚潜紅。", "是時天地氣，正在貞元中。", "千峰雖歷歷，衆樹猶濛濛。", "群動又將作，平秩一日東。", "洒然人欲盡，天理將昭融。", "靜窗自展玩，妙處誰能窮。"]'),
('3e87ce82-610d-4b19-bcfa-7bd9531f1c77','觀赤石龍潭','丘葵','宋','宋诗','song-poetry','','[]','豢擾久不氏，神物失所從。',72,'全唐诗/poet.song.244000.json','["豢擾久不氏，神物失所從。", "碪巖石壁下，豈足爲龍宮。", "亦有萬仞海，茫茫與天通。", "誰言汝爲智，出入人鬼中。", "窮冬天地閉，風雲末由逢。", "泠泠一掬溜，於焉托孤蹤。"]'),
('58a96d79-ea04-4f04-a80b-15ad02e0f5b6','信兒有作依韻勉之','丘葵','宋','宋诗','song-poetry','','[]','母雞啄兒粟，一啄還一呼。',72,'全唐诗/poet.song.244000.json','["母雞啄兒粟，一啄還一呼。", "細腰日祝子，自憐族鰥孤。", "賦形在穹壤，此情誰獨無。", "古來骨肉間，愛深色自愉。", "愧我無黄金，貽以竹與蒲。", "勉哉讀父書，堯桀性不殊。"]'),
('e806f5b8-be88-4b3a-825c-1cf03b05f307','尋從子伯恭不遇','丘葵','宋','宋诗','song-poetry','','[]','我行獨踽踽，聊復尋諸孫。',72,'全唐诗/poet.song.244000.json','["我行獨踽踽，聊復尋諸孫。", "諸孫名有役，誰復相溫存。", "彼茁者汀蘆，上有鷦鷯喧。", "衡門可棲遲，清風自妍暄。", "汲井欲灌圜，灌園當灌根。", "澡身欲樹德，樹德當樹淳。"]'),
('e21fe96c-1b75-41b4-8b81-e867aed40171','趙廷俊毀淫祠詩以美之','丘葵','宋','宋诗','song-poetry','','[]','風霆妙流行，日月互出沒。',132,'全唐诗/poet.song.244000.json','["風霆妙流行，日月互出沒。", "鬼神本良能，一氣自伸屈。", "南方有妖魂，緇衣而血食。", "因訟默祈呼，桎梏脫頃刻。", "逆迪曾靡分，唯事是凶譎。", "吏有廷俊者，謂此非正直。", "宜加以鈇钺，而焚其宮室。", "予聞而壯之，作詩紀其實。", "自從政教弛，刑禍衆所怵。", "憑依以爲奸，白日成異物。", "廷俊慎旃哉，剛方乃終吉。"]'),
('582eb43c-161a-4414-8e94-8368eb1b22b8','送熊退齋歸武夷','丘葵','宋','宋诗','song-poetry','','[]','穆穆朱夫子，於道集大成。',132,'全唐诗/poet.song.244000.json','["穆穆朱夫子，於道集大成。", "嗟予亦私淑，奧義終難明。", "退翁獨何幸，而乃同鄉生。", "雖後百餘載，玄機若親承。", "斯人幸未墜，載道來桐城。", "平生疑惑處，喜得相考評。", "秋風吹庭樹，忽然作離聲。", "吾儕各衰老，何時重合并。", "願言且少住，勿棄斯文盟。", "聖賢千萬語，只在知與行。", "前修倘可企，勗哉共修程。"]'),
('1620129d-d8a2-4a58-8b80-ad23155d781f','古愚兄戒食','丘葵','宋','宋诗','song-poetry','','[]','有美者庭花，謹毋縱牛羊。',72,'全唐诗/poet.song.244000.json','["有美者庭花，謹毋縱牛羊。", "方苞亦方折，其葉何牂牂。", "敦篤哉吾兄，一食不我忘。", "有酒既醑我，又以嘉殽將。", "感兄此意厚，起奉千年觴。", "何以報嘉惠，作善天降祥。"]'),
('d67ba33d-3134-42c1-8055-4052ea86e3fd','北山','丘葵','宋','宋诗','song-poetry','','[]','朝見北山青，暮見北山紫。',88,'全唐诗/poet.song.244000.json','["朝見北山青，暮見北山紫。", "頑然土與石，此色何處起。", "無情草木含清輝，朝露夕陽助明媚。", "四時烟雨姿態異，天機滾滾何曾已。", "人見山上有青天，誰知天在青山裏。", "欲問巨靈知不知，孤鳶飛處白雲起。"]'),
('caa3e1a3-4c83-46c1-bee3-68746477ecc2','次放翁梅花韻','丘葵','宋','宋诗','song-poetry','','[]','冰崖雪谷物未芽，造物破荒開此花。',96,'全唐诗/poet.song.244000.json','["冰崖雪谷物未芽，造物破荒開此花。", "神全形枯近有道，意莊正色知無邪。", "高堅正要飽憂患，放棄何遽愁荒遐。", "移根上苑亦早計，竹籬茅舍真吾家。", "平生自嫌亦自許，妙處可識不可誇。", "金樽翠杓未免俗，篝燈爲試江南茶。"]'),
('fd6166e9-d048-453e-9c2d-4f8ee9dc395e','禽言','丘葵','宋','宋诗','song-poetry','','[]','春泥滑滑雨瀟瀟，田父力作收墜樵。',99,'全唐诗/poet.song.244000.json','["春泥滑滑雨瀟瀟，田父力作收墜樵。", "歸來不敢道姑惡，我自忘却婆餠焦。", "去年冬旱無麥熟，阿婆餠焦難再得。", "門前忽報穀公來，竈冷樽空難接客。", "阿兄提壺沽濁醪，阿弟布穀披短簔。", "不時脫却布褲渡溪水，只愁行不得也哥哥。"]'),
('522e30ae-bd4c-40b8-af88-467e4dfcdd58','次韻吳靜能秦檜','丘葵','宋','宋诗','song-poetry','','[]','故老相傳爲秦檜，飛仙時立凍蛟背。',160,'全唐诗/poet.song.244000.json','["故老相傳爲秦檜，飛仙時立凍蛟背。", "疑是當年丫髻人，憑虛馭氣今安在。", "百千年樹見栽時，新承雨露入昭代。", "托根南極殿下生，巍巍直與天樞對。", "紛紛牛馬已成塵，露葉風枝今幾載。", "是時鸞鳳一來棲，梟狐不敢鳴妖怪。", "一朝名字動至尊，不見尊形空粉繪。", "多少黄冠盡白頭，依神正直人再拜。", "老榛何物敢干名，直根惟有蘇仙愛。", "方今南北同一天，孤標不見貞元會。"]'),
('81fcb10b-e765-4fd7-b9a3-ec427156a722','李養吾董教同安爲作長編','丘葵','宋','宋诗','song-poetry','','[]','一元之根貞下起，勾萌甲拆春陽敷。',224,'全唐诗/poet.song.244000.json','["一元之根貞下起，勾萌甲拆春陽敷。", "千紅萬紫弄晴霽，忽然暗綠繞丘墟。", "霜風厲厲百物遂，枝葉剝落留根株。", "一誠通復心無愧，雖千萬往猶褐夫。", "浩然之氣非襲取，所要與道與義俱。", "勿正勿忘勿助長，活潑潑地惟鳶魚。", "子思喫緊爲人處，鄒孟得之曰養吾。", "千載斷脈無人續，往往舐痔誇得車。", "何期邑泮乃親見，鐸音之來自方壺。", "加之卿相心不動，顧乃下教青衿徒。", "古來揖遜三杯酒，至和薰蒸遍八極。", "聖門狂者得氣象，童冠浴沂風舞雩。", "歎子養浩亦已久，讀書窗前草不除。", "明年春風二三月，不知先生與點無。"]'),
('a00facb8-2047-43b1-9915-2cba10779ec6','七歌效杜陵體  其一','丘葵','宋','宋诗','song-poetry','','[]','景炎元年北人至，撒花初令豪家備。',65,'全唐诗/poet.song.244000.json','["景炎元年北人至，撒花初令豪家備。", "誰梯禍亂敷我民，敲朴日煩無處避。", "富者有銀猶可甦，貧者無銀賣田地。", "嗚呼一歌兮歌已衰，天日不見惟陰霾。"]'),
('c50736bb-115d-4df3-92d5-7f8cd4399700','七歌效杜陵體  其二','丘葵','宋','宋诗','song-poetry','','[]','三宮北狩何時返，猿啼鬼哭塵沙遠。',65,'全唐诗/poet.song.244000.json','["三宮北狩何時返，猿啼鬼哭塵沙遠。", "李陵衛律甘匪人，豈無蔡琰吹胡管。", "江南江北骨成山，箭瘢紛紛劍痕滿。", "嗚呼二歌兮歌未休，潸然出涕滂沱流。"]'),
('eb1dc440-dea0-4608-af63-859624eee9c5','七歌效杜陵體  其三','丘葵','宋','宋诗','song-poetry','','[]','山林嘯聚繁有徒，州家買盡勤招呼。',65,'全唐诗/poet.song.244000.json','["山林嘯聚繁有徒，州家買盡勤招呼。", "縣官被命不敢遜，麒麟出模群狐孤。", "昨者參州紅帕首，高官厚祿恣狂圖。", "嗚呼三歌兮歌三發，天翻地覆綱常滅。"]'),
('a37130a5-338d-4963-886b-f6a8b4dfffa9','七歌效杜陵體  其四','丘葵','宋','宋诗','song-poetry','','[]','督府養兵如養子，帛堆其家粟崇庾。',65,'全唐诗/poet.song.244000.json','["督府養兵如養子，帛堆其家粟崇庾。", "少不如意出怨言，恃功偃蹇驕其主。", "道旁老甿哭告予，未被賊苦被軍苦。", "嗚呼四歌兮歌始宣，悲風爲我吹塵寰。"]'),
('fd812a74-f16a-4dce-9834-4729fb0ea3d7','七歌效杜陵體  其五','丘葵','宋','宋诗','song-poetry','','[]','富兒諧了西園債，身著綠衣足誇詫。',65,'全唐诗/poet.song.244000.json','["富兒諧了西園債，身著綠衣足誇詫。", "那知又有價高人，昨日新官今日罷。", "近來書滿只月餘，白頭老吏慵送迓。", "嗚呼五歌兮歌未足，末世由來多反覆。"]'),
('af71a324-048e-48ca-ad41-93e3ea8ba121','七歌效杜陵體  其六','丘葵','宋','宋诗','song-poetry','','[]','十家九室厨無煙，兒夫仆後妻僵前。',65,'全唐诗/poet.song.244000.json','["十家九室厨無煙，兒夫仆後妻僵前。", "米珠薪桂肉如玉，野無青草飛烏鳶。", "手持空券向何許，官司有印儂無錢。", "嗚呼六歌兮歌愈悲，天下太平竟何時。"]'),
('0669667f-ea7a-4c57-87c6-5acec4435704','七歌效杜陵體  其七','丘葵','宋','宋诗','song-poetry','','[]','我生不辰逢亂離，四方蹙蹙何所之。',67,'全唐诗/poet.song.244000.json','["我生不辰逢亂離，四方蹙蹙何所之。", "欲登山兮有虎豹，欲入海兮有蛟螭。", "歸來歸來磨兜堅，毋與蛟鬭兮毋充虎饑。", "嗚呼七歌兮歌曲罷，猿啼清晝蟲鳴夜。"]'),
('3a58d077-68fc-40cf-a9a9-94048e4463e3','秋園桃花','丘葵','宋','宋诗','song-poetry','','[]','秋園八月開桃花，數枝冷淡無光華。',64,'全唐诗/poet.song.244000.json','["秋園八月開桃花，數枝冷淡無光華。", "北風蕭蕭吹汝寒，汝發非時誰復看。", "牆下牽月顔色鮮，故園欺汝相縈纏。", "何不藏英待時發，自有陽春三月天。"]'),
('9df70ecc-bd7a-4a5e-97cf-1238539dc931','寄龍湖莊','丘葵','宋','宋诗','song-poetry','','[]','鶴髮重來客，龍湖舊日莊。',48,'全唐诗/poet.song.244000.json','["鶴髮重來客，龍湖舊日莊。", "鄉心忽摇曳，春事又蒼茫。", "聒聒水泉動，荒荒野日長。", "殘年厭聲利，吾道在耕桑。"]'),
('d26463d7-c225-4f3c-aad6-0b6b054dbeb4','初六日過江古愚兄送至渡口','丘葵','宋','宋诗','song-poetry','','[]','茅屋亦云好，萍蹤不自由。',48,'全唐诗/poet.song.244000.json','["茅屋亦云好，萍蹤不自由。", "看書猶几上，解纜已沙頭。", "白髮兄和弟，清江夏亦秋。", "相看不忍別，斜日墜汀洲。"]'),
('957d0e63-7787-491e-9ff9-5c97ea975234','顔北城有約看梅徘徊花下','丘葵','宋','宋诗','song-poetry','','[]','千林共摇落，老樹獨蜿蜒。',48,'全唐诗/poet.song.244000.json','["千林共摇落，老樹獨蜿蜒。", "玉立無人處，黄昏欲雪天。", "臨風情脈脈，倚竹靜娟娟。", "身世寒香裏，相看意已仙。"]'),
('e2e63014-f7f7-4203-86e3-ae7109e0a660','入忠軒書院咏蘭','丘葵','宋','宋诗','song-poetry','','[]','階庭暫託根，只與綠苔親。',48,'全唐诗/poet.song.244000.json','["階庭暫託根，只與綠苔親。", "自少枝條分，不爭花卉春。", "輕寒青瘦硬，出檻紫鮮新。", "風雨時吹洗，含芬待主人。"]'),
('fb86d582-2c41-40ed-82e5-726dcaf56b6f','與汝翔晚行','丘葵','宋','宋诗','song-poetry','','[]','偶值忘形友，田間步晚晴。',48,'全唐诗/poet.song.244000.json','["偶值忘形友，田間步晚晴。", "四圍山木合，一片夕陽明。", "倚杖數歸翮，隔溪聞喚聲。", "行來僧寺歇，又得問無生。"]'),
('052c9cfb-1be9-4abf-8c78-842faf16f70f','呈大宗丞求筆戲','丘葵','宋','宋诗','song-poetry','','[]','咄咄人誰識，翩翩老更佳。',48,'全唐诗/poet.song.244000.json','["咄咄人誰識，翩翩老更佳。", "王維不是畫，蘇晉已長齋。", "地靜白生室，天秋黄落階。", "日長用幽意，咫尺到無懷。"]'),
('e9819a16-eb4d-4ec2-a879-a63938fe53af','次呂之壽韻寄肯體','丘葵','宋','宋诗','song-poetry','','[]','甚矣吾衰也，時哉道亦然。',48,'全唐诗/poet.song.244000.json','["甚矣吾衰也，時哉道亦然。", "詩書輿脫輹，歲月箭辭弦。", "所欠惟一死，斯須便百年。", "細思禽與犢，等是食和眠。"]'),
('a6cc4742-9478-4ede-afed-edaa8c853716','寄雪庭老子','丘葵','宋','宋诗','song-poetry','','[]','問訊紫雲老，何時立雪參。',48,'全唐诗/poet.song.244000.json','["問訊紫雲老，何時立雪參。", "生來將滿百，空界直超三。", "泡幻修千劫，佛應同一龕。", "曾師蒙印可，玄諦老方諳。"]'),
('b4549a23-fe95-41aa-9d4e-a9db41c85bba','壽竹西','丘葵','宋','宋诗','song-poetry','','[]','中秋八月朔，人在竹之西。',48,'全唐诗/poet.song.244000.json','["中秋八月朔，人在竹之西。", "講席朝齊聽，吟寮夜獨棲。", "交情今管鮑，清操古夷齊。", "却笑苔磯老，畏人頭愈低。"]'),
('8c708df3-9534-4c41-95a1-e7448b9acd86','寄南劍詹野渡先生','丘葵','宋','宋诗','song-poetry','','[]','賢聖已往古，吾儕空自今。',48,'全唐诗/poet.song.244000.json','["賢聖已往古，吾儕空自今。", "六經尋斷脈，千里遇知音。", "莫笑因緣淺，相期造道深。", "可憐山海隔，無路盍朋簪。"]'),
('a3e496ee-aff8-44e0-be65-c94fedb3d812','送元鼎學士','丘葵','宋','宋诗','song-poetry','','[]','秋風甫聯騎，朔雪又回車。',48,'全唐诗/poet.song.244000.json','["秋風甫聯騎，朔雪又回車。", "北道奇男子，南遊行祕書。", "碧幢留別句，丹陛慶新除。", "頭白逢昭代，吾甘渭水漁。"]'),
('fe72e711-04d9-4e79-8d5f-eb004c4c4e47','贈曹貫之','丘葵','宋','宋诗','song-poetry','','[]','一見如疇昔，人文兩崛奇。',48,'全唐诗/poet.song.244000.json','["一見如疇昔，人文兩崛奇。", "豪來無一世，狂發有千詩。", "浩然乾坤塞，修名臺省知。", "就尋一勺水，神物自應移。"]'),
('fb120b1e-a796-45dd-8e91-e998318466a5','送舶司李郎中','丘葵','宋','宋诗','song-poetry','','[]','朝家三尺法，海舶一帆風。',48,'全唐诗/poet.song.244000.json','["朝家三尺法，海舶一帆風。", "物到琛聲上，人行浪屋中。", "貨因拚命得，廉故秉心公。", "行李清如洗，名應達陛楓。"]'),
('ac4369b0-e628-4aad-9637-97d928c409e0','挽梁丹隠','丘葵','宋','宋诗','song-poetry','','[]','受用伯陽書，萬緣都覺虛。',48,'全唐诗/poet.song.244000.json','["受用伯陽書，萬緣都覺虛。", "達官直桎梏，大厦即籧篨。", "世謂求仙妄，誰知是道餘。", "臨終爲土解，何必淚盈裾。"]'),
('b5d1e983-d0c0-4e19-a46a-5de305b03e32','挽張樗堂','丘葵','宋','宋诗','song-poetry','','[]','與君雖遠隔，自少即相親。',48,'全唐诗/poet.song.244000.json','["與君雖遠隔，自少即相親。", "老失同年友，鄉無好善人。", "樗堂春絕迹，蒿里暗傷神。", "丹旐歸何處，風霜故冢濱。"]'),
('5815e8a4-9c61-47d8-9406-d69a28516de1','讀石隠淡吟藁','丘葵','宋','宋诗','song-poetry','','[]','借師新藁讀，睡睫不曾交。',48,'全唐诗/poet.song.244000.json','["借師新藁讀，睡睫不曾交。", "璧月沉寒瀨，琪花著老梢。", "一吟三歎咏，雙字幾推敲。", "曉雨驅炎熱，僧窗得盡鈔。"]'),
('58ad049f-efdf-4e19-a9cf-51e7254db979','寄陳儒正','丘葵','宋','宋诗','song-poetry','','[]','論心纔暑夕，別後已凉秋。',48,'全唐诗/poet.song.244000.json','["論心纔暑夕，別後已凉秋。", "月照陳蕃榻，風生王粲樓。", "哀音蟲外笛，遠棹雁邊舟。", "欲寫相思意，題詩寄水流。"]'),
('b30714fa-aa16-47ea-a714-f2f703520413','離相院','丘葵','宋','宋诗','song-poetry','','[]','一夕僧留宿，翛然萬慮空。',48,'全唐诗/poet.song.244000.json','["一夕僧留宿，翛然萬慮空。", "草分仙掌綠，花發御袍紅。", "白鳥松梢雪，玄談麈尾風。", "因悲人世上，終日業塵中。"]'),
('405a4849-2697-4139-81d7-5c48002efda4','秘藏院','丘葵','宋','宋诗','song-poetry','','[]','纔入空門裏，塵心便欲拋。',48,'全唐诗/poet.song.244000.json','["纔入空門裏，塵心便欲拋。", "土花生石縫，野蔓上林梢。", "棟老蜂鑽穴，簷低雀結巢。", "僧中無賈島，得句自推敲。"]'),
('1e5e2295-b6f4-426f-85d8-1f103c2f000e','幽趣','丘葵','宋','宋诗','song-poetry','','[]','幅巾篁竹下，幽趣與僧同。',48,'全唐诗/poet.song.244000.json','["幅巾篁竹下，幽趣與僧同。", "坐對忘憂草，行歌解慍風。", "鴨頭池水綠，猩血石榴紅。", "解作晴天雪，松梢鷺一叢。"]'),
('89f251c0-b873-4898-974d-efbb94eb0d35','寄呈張教諭','丘葵','宋','宋诗','song-poetry','','[]','天欲昌吾道，君來董縣庠。',48,'全唐诗/poet.song.244000.json','["天欲昌吾道，君來董縣庠。", "壇荒猶杏樹，水落且芹香。", "欲與二三子，皈依數仞牆。", "若爲鷗鷺伴，留住水雲鄉。"]'),
('d82f2dd8-b916-4e5a-b130-0589e37ad16e','書山翁房壁','丘葵','宋','宋诗','song-poetry','','[]','山翁有山癖，盡日對山青。',48,'全唐诗/poet.song.244000.json','["山翁有山癖，盡日對山青。", "盂水晨煎茗，爐香夜誦經。", "雨畦蔬長甲，風徑竹添丁。", "獨有曾游客，清癯似鶴形。"]'),
('e6f81092-78b9-4678-acda-052d4bf680a6','出院門閒步','丘葵','宋','宋诗','song-poetry','','[]','出愛前村景，歸穿薄暮煙。',48,'全唐诗/poet.song.244000.json','["出愛前村景，歸穿薄暮煙。", "鳥飛虛碧裏，人在落紅邊。", "近晚山容淡，新晴稻色鮮。", "殷勤一溪水，清到院門前。"]'),
('6bb49886-99fb-46a5-80fe-80a54bec4858','偶成','丘葵','宋','宋诗','song-poetry','','[]','風雨三間屋，乾坤一腐儒。',48,'全唐诗/poet.song.244000.json','["風雨三間屋，乾坤一腐儒。", "營生妻笑拙，學古客言迂。", "坐久燈花落，吟成硯水枯。", "方書俱遍覽，無藥可醫愚。"]'),
('a28ffa26-9ee1-4462-99cf-fb8ce58320ea','白鷺','丘葵','宋','宋诗','song-poetry','','[]','衆禽無此格，玉立一閒身。',48,'全唐诗/poet.song.244000.json','["衆禽無此格，玉立一閒身。", "清似參禪客，癯如辟穀人。", "綠秧青草外，枯葦敗荷濱。", "口體猶相累，終朝覓細鱗。"]'),
('62a807a8-4dd0-4536-94d1-e0927b3af09e','步院前溪水','丘葵','宋','宋诗','song-poetry','','[]','偶出山門去，乘凉步淺沙。',48,'全唐诗/poet.song.244000.json','["偶出山門去，乘凉步淺沙。", "溪流盤略彴，岸沫上槎枒。", "野拓天圍大，風吹日脚科。", "吟成無與語，獨立數歸鴉。"]'),
('cbf0ce72-d737-486c-9ce1-956101948746','哭呂樸卿先生  其一','丘葵','宋','宋诗','song-poetry','','[]','已擬侍荷橐，俄抽似葉身。',48,'全唐诗/poet.song.244000.json','["已擬侍荷橐，俄抽似葉身。", "甘爲南地鬼，不作北朝臣。", "屋壁遺文壞，鄰州戰血新。", "劫灰飛未盡，碑碣托何人。"]'),
('468de690-bbc5-497b-bf37-1e95894e5425','哭呂樸卿先生  其二','丘葵','宋','宋诗','song-poetry','','[]','潮士瞻韓木，莆民愛召棠。',48,'全唐诗/poet.song.244000.json','["潮士瞻韓木，莆民愛召棠。", "名隨天共遠，身與物俱亡。", "血碧一時恨，汗青千載香。", "玄虬方隕蹶，螾蛭恣飛揚。"]'),
('c7cc1350-3d03-4bc4-a394-4b5d4b7d5dc7','哭呂樸卿先生  其三','丘葵','宋','宋诗','song-poetry','','[]','斯文天欲喪，疑義有誰祛。',48,'全唐诗/poet.song.244000.json','["斯文天欲喪，疑義有誰祛。", "無復諄諄誘，空令咄咄書。", "秋風冢上木，夜月墓邊廬。", "每與諸孤道，相看淚滿裾。"]'),
('1a9994c6-f608-4d00-9713-747fa133709a','端午','丘葵','宋','宋诗','song-poetry','','[]','世亂逢端午，凄凉弔古心。',48,'全唐诗/poet.song.244000.json','["世亂逢端午，凄凉弔古心。", "空存蒲長綠，不見黍包金。", "蛇壑橫人骨，鰲江絕古音。", "追思前日事，愁比海波深。"]'),
('3e5c550a-dc0d-41bd-a9cd-c281f897000b','倚杖','丘葵','宋','宋诗','song-poetry','','[]','爲憐情景好，倚杖立還移。',48,'全唐诗/poet.song.244000.json','["爲憐情景好，倚杖立還移。", "海近雲來濕，波平日下遲。", "歸牛行礫确，幽鳥語淪漪。", "覓句心將嘔，傍人過不知。"]'),
('74efb074-0893-4e9d-80a7-5bf109fdfc27','過野塘用杜老韻','丘葵','宋','宋诗','song-poetry','','[]','蛙浮成出字，雨點作圓紋。',48,'全唐诗/poet.song.244000.json','["蛙浮成出字，雨點作圓紋。", "荷葉多於草，炊煙遠似雲。", "水清魚可數，村近鴨成羣。", "何日營茅屋，來茲避世紛。"]'),
('5ac055dc-6e21-4985-8fa0-58328491e80f','月中與諸友還在沙溪','丘葵','宋','宋诗','song-poetry','','[]','爲愛江頭月，回環宿鷺汀。',48,'全唐诗/poet.song.244000.json','["爲愛江頭月，回環宿鷺汀。", "露濃如潑水，天淡欲無星。", "樹色依月黑，螢光出竹青。", "夜深幽興極，瘦影自伶俜。"]'),
('4542d88c-b609-4ee0-ba82-a0a6a7b5a4d1','贈義上人','丘葵','宋','宋诗','song-poetry','','[]','足跡遍天涯，何年始出家。',48,'全唐诗/poet.song.244000.json','["足跡遍天涯，何年始出家。", "去時雙不借，歸日一袈裟。", "有句堪題壁，無魔敢散花。", "至今清夜話，猶自带煙霞。"]'),
('7159e023-01e1-4233-b69d-676ad3d53665','送陳判之邑庠','丘葵','宋','宋诗','song-poetry','','[]','君去採芹藻，那知事不同。',48,'全唐诗/poet.song.244000.json','["君去採芹藻，那知事不同。", "乾坤已易主，禮樂尚儒宮。", "雨過山仍綠，春歸花盡紅。", "悠悠聖門意，千古獨清風。"]'),
('10f618cd-85db-40b4-8498-264cb9a6e68c','遊秘藏院呈老叟','丘葵','宋','宋诗','song-poetry','','[]','法藏千年在，何人結構功。',48,'全唐诗/poet.song.244000.json','["法藏千年在，何人結構功。", "寒潭空夜月，老檜易秋風。", "我問四奇觀，師云一切空。", "因之悟真境，只在太虛中。"]'),
('e409b648-1084-42b0-804c-4b112bdfc65e','寄林簿','丘葵','宋','宋诗','song-poetry','','[]','一別又一載，相思入夢頻。',48,'全唐诗/poet.song.244000.json','["一別又一載，相思入夢頻。", "以予拙生計，知子不爲貧。", "鼠跡陶瓶粟，蛛絲范甑塵。", "莫將憔悴意，說與得時人。"]'),
('cc828870-690b-4bf9-9cb3-f66403475229','塵世','丘葵','宋','宋诗','song-poetry','','[]','塵世無暇日，偷閒到曉亭。',48,'全唐诗/poet.song.244000.json','["塵世無暇日，偷閒到曉亭。", "橋陰界水綠，燒迹斷山青。", "石瘦牛磨角，簷空雀墜翎。", "暮笳風外響，愁坐若爲聽。"]'),
('379b71cd-b8a4-4eef-9201-38c7e24ae0f9','泛舟','丘葵','宋','宋诗','song-poetry','','[]','泛舟游碧渚，避世作漁翁。',48,'全唐诗/poet.song.244000.json','["泛舟游碧渚，避世作漁翁。", "試問千鍾祿，何如一釣筒。", "雨添春後水，帆漲晚來風。", "緡捲看魚上，停橈倚荻叢。"]'),
('406c13a8-cf63-491f-8538-31ff3203ae33','田舍  其一','丘葵','宋','宋诗','song-poetry','','[]','久旱割豐穰，群童拾穗忙。',48,'全唐诗/poet.song.244000.json','["久旱割豐穰，群童拾穗忙。", "早炊留客飯，新釀喚翁嘗。", "庭上豆萁滿，籬邊蔬甲長。", "腰鐮砍草木，準擬撐欹桑。"]'),
('bf5aabf1-e80c-4e2e-b4fd-cdcbf11863cc','田舍  其二','丘葵','宋','宋诗','song-poetry','','[]','亂後無雞犬，昏到足蚋蚊。',48,'全唐诗/poet.song.244000.json','["亂後無雞犬，昏到足蚋蚊。", "有翁如老鶴，蹙頞說官軍。", "理穀爲春種，鞭禾到夜分。", "與兒再三話，衣食在辛勤。"]'),
('a83c405f-6220-4d1b-910f-ed1463f38d48','田舍  其三','丘葵','宋','宋诗','song-poetry','','[]','片雲頭上黑，凍雨自西來。',48,'全唐诗/poet.song.244000.json','["片雲頭上黑，凍雨自西來。", "促婦收餘穀，呼童拾爨柴。", "堆禾披草蓋，移菜傍畦栽。", "却憶翁年老，前村醉未回。"]'),
('1f895318-1c31-4f5b-abdd-a7e3b9729215','田舍  其四','丘葵','宋','宋诗','song-poetry','','[]','割餘田有鶴，食罷案多蠅。',48,'全唐诗/poet.song.244000.json','["割餘田有鶴，食罷案多蠅。", "裒穀爲秋賽，燃薪當夜燈。", "老牛背觳觫，爨婦髻鬅鬙。", "應是無心問，朝家發與興。"]'),
('ec6d5781-3f12-4db7-ac06-33dabaea877e','惡况','丘葵','宋','宋诗','song-poetry','','[]','惡况有誰知，僵妻與仆兒。',48,'全唐诗/poet.song.244000.json','["惡况有誰知，僵妻與仆兒。", "無人乞顔米，有客泣楊岐。", "浩劫天難免，凶年鬼亦饑。", "但言身長在，不敢恨流離。"]'),
('612f640b-1cc7-4a1e-b04f-868f98952ba0','貧','丘葵','宋','宋诗','song-poetry','','[]','相見盡言貧，能貧得幾人。',48,'全唐诗/poet.song.244000.json','["相見盡言貧，能貧得幾人。", "文成休送鬼，錢乏那通神。", "形瘦何妨鶴，衣懸一任鶉。", "饑來眠仰屋，鼻息撼梁塵。"]'),
('cf895ca5-0aad-42e1-962f-1a1250af4458','初六早過後浦莊','丘葵','宋','宋诗','song-poetry','','[]','秋晚村莊憩，青山對掩扉。',48,'全唐诗/poet.song.244000.json','["秋晚村莊憩，青山對掩扉。", "輕風隨步屧，殘露濕征衣。", "水滿菰蒲亂，田荒鸛鶴飛。", "欲行還小立，旅思重依依。"]'),
('ae56d881-f52d-4526-b717-fcebef8e5726','九日','丘葵','宋','宋诗','song-poetry','','[]','海山秋索莫，不見菊花開。',48,'全唐诗/poet.song.244000.json','["海山秋索莫，不見菊花開。", "節與貧相棄，年將老共催。", "艱難思故里，牢落對殘盃。", "舊日登高伴，今無一個來。"]'),
('ecd29e25-4ee7-4c14-96e8-e3d0b9036f93','瑞光亭有作','丘葵','宋','宋诗','song-poetry','','[]','終年蕭寺裏，人跡往來稀。',48,'全唐诗/poet.song.244000.json','["終年蕭寺裏，人跡往來稀。", "雀踏梁塵落，蜂穿木屑飛。", "佛幡書古偈，僧壁掛禪衣。", "此景惟予愛，冷然契道機。"]'),
('3a7c82e4-3d85-4ede-8a82-eb5fc4e54de6','遊賢坂書贈可大','丘葵','宋','宋诗','song-poetry','','[]','十月寒猶未，幽人樂自便。',48,'全唐诗/poet.song.244000.json','["十月寒猶未，幽人樂自便。", "看山行覓句，掃石坐談玄。", "一徑藤蘿月，數家桑柘煙。", "舊時釣魚處，枯木倒寒泉。"]'),
('a4ad0896-9ae8-4e6d-b27a-8edf637e54ca','雨後閑步','丘葵','宋','宋诗','song-poetry','','[]','洗天風雨過，炎暑漠然收。',48,'全唐诗/poet.song.244000.json','["洗天風雨過，炎暑漠然收。", "偶爾掩門去，因之入寺遊。", "農畦瓜蔓長，僧圃貝花稠。", "自笑生涯拙，空餘一髻秋。"]'),
('e6798bd0-8323-458d-a78f-51618b66e028','題章法山房','丘葵','宋','宋诗','song-poetry','','[]','四壁羲文卦，曾因學易居。',48,'全唐诗/poet.song.244000.json','["四壁羲文卦，曾因學易居。", "今來三十載，只有一空廬。", "境寂含群動，窗明納太虛。", "無人悟玄理，梅竹翠扶疏。"]'),
('6ae88aed-11c7-4199-8729-d5eb9dff09fa','寄呂之壽','丘葵','宋','宋诗','song-poetry','','[]','一燈清夜話，覺子頗真情。',48,'全唐诗/poet.song.244000.json','["一燈清夜話，覺子頗真情。", "世已無前輩，方予畏後生。", "天涯共流落，歲晚獨無成。", "桐下來春約，飛鴻望寄聲。"]'),
('7e1a9ced-c24e-4f63-a791-774d59e590e5','入冬半月餘二麥未種忽然一雨','丘葵','宋','宋诗','song-poetry','','[]','村莊三日雨，清曉怯憑欄。',48,'全唐诗/poet.song.244000.json','["村莊三日雨，清曉怯憑欄。", "洒地紛紛白，隨風陣陣寒。", "不愁客衣薄，且爲老農歡。", "已有芃芃意，來春歲計寬。"]'),
('6bf4eaf8-7083-45a1-bf98-a455a4240e84','乘除','丘葵','宋','宋诗','song-poetry','','[]','若問乘除法，須當健補貧。',48,'全唐诗/poet.song.244000.json','["若問乘除法，須當健補貧。", "何如窮到骨，更有病纏身。", "忽忽又將老，蒼蒼更不神。", "此生吾自斷，蓑笠一閒人。"]'),
('00a663da-193f-48e3-b00e-5931b50a9a18','和匏齋菊花','丘葵','宋','宋诗','song-poetry','','[]','東籬曾手種，頼以制頹年。',48,'全唐诗/poet.song.244000.json','["東籬曾手種，頼以制頹年。", "白髮經秋別，黄花入夢圓。", "一場蜂蝶後，老圃雪霜前。", "不是躭幽隠，淵明地自偏。"]'),
('8eb76880-9b9f-4a17-97a7-ca9e4d1fff09','秋夜','丘葵','宋','宋诗','song-poetry','','[]','中秋愛親友，欲別不勝愁。',48,'全唐诗/poet.song.244000.json','["中秋愛親友，欲別不勝愁。", "此去無多日，羈情可奈秋。", "山寒猶碧樹，水落正滄洲。", "莫道非吾土，今冬尚此留。"]'),
('aa36b2f5-249d-4e0a-b50a-9d9c7ab4b65b','寄槐庭','丘葵','宋','宋诗','song-poetry','','[]','吾道付滄浪，衰年尚異鄉。',48,'全唐诗/poet.song.244000.json','["吾道付滄浪，衰年尚異鄉。", "畏人江草合，懷舊暮雲長。", "老我已無用，如君終未忘。", "天寒無過雁，夜夜獨鳴蛩。"]'),
('94a1f488-0172-4716-ad6d-dbaf255ca4b8','悠悠','丘葵','宋','宋诗','song-poetry','','[]','江上形容老，竹間窗戶秋。',48,'全唐诗/poet.song.244000.json','["江上形容老，竹間窗戶秋。", "悠悠忘歲月，落落少交遊。", "無食令兒瘦，有詩消客愁。", "古今多少事，卷易在床頭。"]'),
('5601c7a0-bd11-4732-8ed8-499403a9c3e0','四月朔日曉起候呂之壽','丘葵','宋','宋诗','song-poetry','','[]','清辰未巾櫛，遠遠望山阿。',48,'全唐诗/poet.song.244000.json','["清辰未巾櫛，遠遠望山阿。", "一夕已如此，長年其奈何。", "高齋空寂寞，今日始清和。", "可惜一樽酒，驪駒又欲歌。"]'),
('ff176c80-40e6-4087-a09a-25fb735dc4c5','次韻呂之壽見憶','丘葵','宋','宋诗','song-poetry','','[]','日暮客送客，此情悲復悲。',48,'全唐诗/poet.song.244000.json','["日暮客送客，此情悲復悲。", "棲棲吾老矣，寂寂子何之。", "跬步便相憶，論心未有期。", "江湖成底事，空使素衣緇。"]'),
('be4072ea-7a2b-4c41-953c-ec12e4bbb443','壽蕭東海','丘葵','宋','宋诗','song-poetry','','[]','樂哉東海老，天與以遐齡。',48,'全唐诗/poet.song.244000.json','["樂哉東海老，天與以遐齡。", "前一輩人物，爲諸生典型。", "頭因嗜書白，眼不要人青。", "歲歲桑蓬旦，人間活壽星。"]'),
('37866e3a-1630-4306-9487-9cf987dfe37d','范掌書','丘葵','宋','宋诗','song-poetry','','[]','出佐繡衣使，八州人共歡。',48,'全唐诗/poet.song.244000.json','["出佐繡衣使，八州人共歡。", "一句司范筆，六計問周官。", "雁鶩手持進，豺狼膽自寒。", "豈惟重臺省，風采動朝端。"]'),
('6d803035-c7d4-4fc1-907d-64acd0f41d52','葉掌書','丘葵','宋','宋诗','song-poetry','','[]','陽復天心動，春回五葉中。',48,'全唐诗/poet.song.244000.json','["陽復天心動，春回五葉中。", "梅梢足生意，柏府早清風。", "身任八州寄，手持三尺公。", "可憐芹泮士，空自獻詩筒。"]'),
('3306f598-2ce1-4e87-8b32-d054499b48fe','貧病','丘葵','宋','宋诗','song-poetry','','[]','貧與病相約，貧來病亦來。',48,'全唐诗/poet.song.244000.json','["貧與病相約，貧來病亦來。", "有僧時饋藥，無鬼敢輸財。", "酒債償仍欠，醫書閤又開。", "安貧吾自愛，且遣病魔回。"]'),
('ab859114-1d7d-474b-89d5-4d9711886e9a','浮名','丘葵','宋','宋诗','song-poetry','','[]','不起浮名想，都緣耐寂寥。',48,'全唐诗/poet.song.244000.json','["不起浮名想，都緣耐寂寥。", "小齋坐聽雨，野渡立看潮。", "歲月吟邊過，憂愁醉裏消。", "早知書分淺，悔不學漁樵。"]'),
('1f6f52ed-db1f-4475-8341-4795a30d72de','養拙','丘葵','宋','宋诗','song-poetry','','[]','養拙干戈際，逃名山水邊。',48,'全唐诗/poet.song.244000.json','["養拙干戈際，逃名山水邊。", "疏泉妨蟻過，掃地愜牛眠。", "竟日雲籠樹，何時雨洗天。", "入門兒女聒，恨未斷塵緣。"]'),
('8f3744e8-5929-4173-804f-3b41b4849e2c','慈濟行祠','丘葵','宋','宋诗','song-poetry','','[]','上人棲息地，况近佛莊嚴。',48,'全唐诗/poet.song.244000.json','["上人棲息地，况近佛莊嚴。", "亂蘚緘新甃，閒花覆古簷。", "浯山青入眼，榕樹紫垂髯。", "獨步秋祠晚，雲間月一鐮。"]'),
('164d3dba-bd03-4521-a761-2302157028d9','閒居','丘葵','宋','宋诗','song-poetry','','[]','樹月紛紛白，溪流練練青。',48,'全唐诗/poet.song.244000.json','["樹月紛紛白，溪流練練青。", "畦蔬先雨種，徑草未春生。", "井近通鄰汲，橋崩斷客行。", "閒居寂無事，觴咏敘幽情。"]'),
('ec4e3d42-02dd-4c72-8775-4eaf5ee2192c','杜鵑花','丘葵','宋','宋诗','song-poetry','','[]','望帝千年魄，春山幾度風。',48,'全唐诗/poet.song.244000.json','["望帝千年魄，春山幾度風。", "聲聲向誰白，歲歲作花紅。", "寂寞荒烟裏，妖嬈細雨中。", "可憐濺成血，無復見蠶叢。"]'),
('52f2efc5-9b48-4b03-912c-3e8cf1221815','送千巖摘稿還仲仁','丘葵','宋','宋诗','song-poetry','','[]','借得千巖一卷詩，吟窗盡日不停披。',64,'全唐诗/poet.song.244000.json','["借得千巖一卷詩，吟窗盡日不停披。", "蒼波溜雨岷峨柏，赤石封苔岣嶁碑。", "不是胸中橫屴崱，如何筆下許瑰奇。", "還君此寶文房裏，應有神明爲護持。"]'),
('43557366-8b44-425e-996f-bc8b5a27d6c6','題誼上人石室','丘葵','宋','宋诗','song-poetry','','[]','接石爲巢瓦縫欹，家風惟有白雲知。',64,'全唐诗/poet.song.244000.json','["接石爲巢瓦縫欹，家風惟有白雲知。", "連筒遠取煎茶水，種竹先尋掛衲枝。", "庵小偏涵新世界，山空不見舊亭池。", "清宵一段西來意，林影參差月上時。"]'),
('4338ad79-05e2-4294-9d91-13a0eb58f354','沙頭玩月','丘葵','宋','宋诗','song-poetry','','[]','萬片魚鱗淡欲收，橫空不碍素光流。',64,'全唐诗/poet.song.244000.json','["萬片魚鱗淡欲收，橫空不碍素光流。", "山河寂寂千年事，風露娟娟五月秋。", "且作希夷閒枕石，惜無李白共登舟。", "細看白兔何曾夜，應使深山魍魎愁。"]'),
('cd593eb2-1750-4baf-965a-3c30e4431798','春花','丘葵','宋','宋诗','song-poetry','','[]','花萼相承二月時，深紅淺紫總皆宜。',64,'全唐诗/poet.song.244000.json','["花萼相承二月時，深紅淺紫總皆宜。", "好春安得長爲主，落葉那能再上枝。", "爛漫不因晴日麗，披離非爲晚風吹。", "世間榮耀霎時事，誤盡世人人不知。"]'),
('ee7a1ad7-7124-4906-b68c-12dc0da98fbd','答城中友人相勉求官','丘葵','宋','宋诗','song-poetry','','[]','愁來自唱五噫歌，名利場中脚豈牢。',64,'全唐诗/poet.song.244000.json','["愁來自唱五噫歌，名利場中脚豈牢。", "君看青衫求熱炙，我憐赤子有寒號。", "鶴沾衛祿猶堪薄，松受秦封豈足高。", "家在荻蘆叢畔住，分當蓑笠釣江臯。"]'),
('2b8d903a-a0ed-4fcd-93d0-f77a442944ef','題楊子岩','丘葵','宋','宋诗','song-poetry','','[]','抗塵走俗令人憎，因覓桃源作此行。',64,'全唐诗/poet.song.244000.json','["抗塵走俗令人憎，因覓桃源作此行。", "畏日燒空時事惡，飛泉瀉石道心生。", "青天盡處孤舟渺，好鳥鳴時萬壑清。", "一老頭陀癯似鶴，殷勤煮水爨風鐺。"]'),
('530b2514-12e1-4955-9a7f-8d934ffb8003','聞復卿欲訪詩以促之','丘葵','宋','宋诗','song-poetry','','[]','五年不見復卿回，有客傳言卿欲來。',64,'全唐诗/poet.song.244000.json','["五年不見復卿回，有客傳言卿欲來。", "苔石生塵親手掃，蓬門久閉令兒開。", "蒼波摇月銀成片，白鷺巢松雪作堆。", "料得城中無此景，速宜相就倒金樽。"]'),
('2a856f1e-84ed-4d13-9913-278aae7a7df8','重遊離相院','丘葵','宋','宋诗','song-poetry','','[]','三年掛搭此叢林，今日重來思轉深。',64,'全唐诗/poet.song.244000.json','["三年掛搭此叢林，今日重來思轉深。", "雨過殘陽如月色，風來老樹作潮音。", "青山歷歷留人住，白鷺悠悠契我心。", "日暮荒村苦無伴，虛廊曳杖自行吟。"]'),
('e382b204-df8e-44ee-ad01-92986a04e924','寄高尹','丘葵','宋','宋诗','song-poetry','','[]','桐下歸來學釣魚，歲寒相伴只鷗鳬。',64,'全唐诗/poet.song.244000.json','["桐下歸來學釣魚，歲寒相伴只鷗鳬。", "何期天上郎官宰，肯到江邊處士廬。", "仲蔚自憐頭似雪，阿勤豈解唾成珠。", "郎君東閣相看久，莫但清吟廢讀書。"]'),
('cd2c5d26-fcfe-4085-9ebe-a7756270ae93','吳天遊竹莊諸公','丘葵','宋','宋诗','song-poetry','','[]','市塵不碍古招提，笑踏西風暫此棲。',64,'全唐诗/poet.song.244000.json','["市塵不碍古招提，笑踏西風暫此棲。", "松喜客來如解語，鳥知僧定不曾啼。", "問禪爪向維摩合，覓句頭因領當低。", "恐見黄花歸未得，雲間何處可攀躋。"]'),
('19f6ab98-2c47-440b-a84b-e3d549ae098b','與所盤諸君會石幡還和杜老曲江韻','丘葵','宋','宋诗','song-poetry','','[]','青禽竹上弄毛衣，飛來簷頭喚不歸。',64,'全唐诗/poet.song.244000.json','["青禽竹上弄毛衣，飛來簷頭喚不歸。", "清景每於詩裏見，羈愁惟到海邊稀。", "僧回古殿山礬落，客散風齋蝙蝠飛。", "獨得青山已惆悵，此情猶是片時違。"]'),
('7d3d0753-6dc6-41b9-9c8d-affa883e9ffa','暮雨','丘葵','宋','宋诗','song-poetry','','[]','幾月環城萬騎屯，一朝聞韃便南奔。',64,'全唐诗/poet.song.244000.json','["幾月環城萬騎屯，一朝聞韃便南奔。", "龍枯未必還憂螘，牛瘠胡爲莫僨豚。", "典午既衰無管仲，吐蕃方熾有懷恩。", "臨風一掬英雄淚，散作彌天暮雨昏。"]'),
('c797ffba-dd86-4997-b216-2fddadcd22fc','秋興  其一','丘葵','宋','宋诗','song-poetry','','[]','千年成敗事悠悠，獨眺川原滿目秋。',64,'全唐诗/poet.song.244000.json','["千年成敗事悠悠，獨眺川原滿目秋。", "底處歸航來遠浦，何人吹笛倚高樓。", "山和疊疊寒雲逈，水带瀟瀟暮雨流。", "回首故家零落盡，樽前誰與語離愁。"]'),
('d22ecacc-bb15-4b9a-a0bb-888b0b80c4bc','秋興  其二','丘葵','宋','宋诗','song-poetry','','[]','天下四時秋最慘，况於人世尚流離。',64,'全唐诗/poet.song.244000.json','["天下四時秋最慘，况於人世尚流離。", "向來犬吠雞鳴處，今見猿啼鬼哭悲。", "淚洒黄花金燦爛，寒生白骨玉參差。", "滿山寂寞秋梧冷，正是愁腸欲斷時。"]'),
('80cc0996-6afc-47bd-8b1c-0b890d89b1e1','怪事','丘葵','宋','宋诗','song-poetry','','[]','怪事年來見未曾，岸今爲谷谷爲陵。',64,'全唐诗/poet.song.244000.json','["怪事年來見未曾，岸今爲谷谷爲陵。", "可憐龍向靈湫蟄，忍見猱來古木升。", "四載干戈多白骨，半宵風雨獨青燈。", "腐儒未識皇天意，不信荆舒竟莫懲。"]'),
('a4b718b0-3b42-48a5-bd6b-bf2ca9721c66','門巷','丘葵','宋','宋诗','song-poetry','','[]','門巷蕭條絕市聲，吟肩終日聳崚嶒。',64,'全唐诗/poet.song.244000.json','["門巷蕭條絕市聲，吟肩終日聳崚嶒。", "瘦如華表秋來鶴，貧似叢林旦過僧。", "渴吻漫消茶一碗，枯腸不飽稻三升。", "交遊豈是相違意，四十無聞自可憎。"]'),
('e578a01a-a51f-46d8-9db0-4f5d114fe3ee','和義兄詩畢忽憶竹莊石隠二老寄詩一首煩爲問訊','丘葵','宋','宋诗','song-poetry','','[]','爲向東林問起居，更詢李白近何如。',64,'全唐诗/poet.song.244000.json','["爲向東林問起居，更詢李白近何如。", "携琴想對青霞頂，覓句應巡碧玉除。", "無復風流陪二老，空憐憔悴似三閭。", "冰霜凜凜河流斷，安得雙魚送尺書。"]'),
('24f21bc3-a8c3-43c5-a4ed-306d190203bd','獨行','丘葵','宋','宋诗','song-poetry','','[]','孤烟落日是何村，向晚村舂隔水聞。',64,'全唐诗/poet.song.244000.json','["孤烟落日是何村，向晚村舂隔水聞。", "白鳥遠來全似蝶，紅霞淡去却成雲。", "愁同落葉飛無數，淡比秋山瘦幾分。", "客寄他鄉元寂寞，獨行不是故離群。"]'),
('23a62394-6bbb-412e-aef5-1b366eacb9ba','與應得李洋歸','丘葵','宋','宋诗','song-poetry','','[]','花時莫負此良辰，信杖閒行寂寞濱。',64,'全唐诗/poet.song.244000.json','["花時莫負此良辰，信杖閒行寂寞濱。", "日入山頭成鶴頂，風吹沙磧皺魚鱗。", "飛來白鷺全成雪，倒去枯松半樹春。", "似此江山孤絕處，故應著此苦吟人。"]'),
('9906af62-5302-44a5-9ecf-136c7292e39c','江鄉','丘葵','宋','宋诗','song-poetry','','[]','蘆荻叢邊日正長，人間樂處是江鄉。',64,'全唐诗/poet.song.244000.json','["蘆荻叢邊日正長，人間樂處是江鄉。", "溪童釣艇分魚閙，蠶婦山爐煮繭香。", "疏雨漏天青破碎，衝風滾浪白猖狂。", "鷗沙犢草皆詩思，毋怪幽人覓句忙。"]'),
('43e25e6d-d3d6-42d6-857f-58c2fdfe9284','自知','丘葵','宋','宋诗','song-poetry','','[]','古寺棲身又兩期，西風吹我鬢成絲。',64,'全唐诗/poet.song.244000.json','["古寺棲身又兩期，西風吹我鬢成絲。", "俗兒往往貌相敬，吾道悠悠心自知。", "盡去皮毛方是學，若無情性定非詩。", "可憐千載相傳授，只爲秦人煨燼餘。"]'),
('2f705a41-e9d3-458a-bbdc-5f08fa733d06','次所盤山村','丘葵','宋','宋诗','song-poetry','','[]','溪外青山山外村，數間茅屋掩柴門。',64,'全唐诗/poet.song.244000.json','["溪外青山山外村，數間茅屋掩柴門。", "青裙竈下偷窺客，白髮堂中笑弄孫。", "乞火煮茶燒土銼，隔籬貰酒舉匏尊。", "梅花不解留人住，山路歸來已夕昏。"]'),
('261d31da-08a0-4bee-b779-d20ec8b6eacf','寓居姚家村','丘葵','宋','宋诗','song-poetry','','[]','平頭五十滄江叟，寄跡三家桑柘村。',64,'全唐诗/poet.song.244000.json','["平頭五十滄江叟，寄跡三家桑柘村。", "樽酒不知誰主客，柬書相伴過晨昏。", "有時獨步來沙際，盡日清談倚樹根。", "一任傍人笑迂闊，此心欲與白鷗論。"]'),
('d995e3db-a419-422c-a61e-801bb0cb6413','麥秋和所盤休字韻','丘葵','宋','宋诗','song-poetry','','[]','片片桃花逐水流，三分春色二分休。',64,'全唐诗/poet.song.244000.json','["片片桃花逐水流，三分春色二分休。", "禁烟時節家家雨，種麥田園處處秋。", "山際夕陽猶觳觫，林梢曉露忽軥輈。", "客中物候催人老，那更分成兩地愁。"]'),
('cb7e036a-1e75-4839-af47-6d156499491f','和意行韻','丘葵','宋','宋诗','song-poetry','','[]','一枝筇竹度年華，自愛藤陰夾雨涯。',64,'全唐诗/poet.song.244000.json','["一枝筇竹度年華，自愛藤陰夾雨涯。", "野叟笑予衣落魄，牧童見客手交叉。", "染成衆綠桑初椹，落盡千紅楝始花。", "步至橋西水窮處，却隨黄犢還吾家。"]'),
('ded9e3c2-36b5-4c63-a8fe-7a5ade0bd071','移居  其一','丘葵','宋','宋诗','song-poetry','','[]','移居山北向山南，天遣清風接笑談。',64,'全唐诗/poet.song.244000.json','["移居山北向山南，天遣清風接笑談。", "無數鳬雛穿稻塍，一群鸂鶩語茭潭。", "鷺臨清泚貪心起，蓮到黄昏笑靨含。", "却憶姚家古藤下，烏巾掛了旦眠酣。"]'),
('d7843a3f-971b-43d7-864b-77c43a20a20d','移居  其二','丘葵','宋','宋诗','song-poetry','','[]','田家一路到村南，盡是農人野叟談。',64,'全唐诗/poet.song.244000.json','["田家一路到村南，盡是農人野叟談。", "鳥過江來平入樹，牛沿堤去倒行潭。", "蜻蜓影下波紋皺，䆉䅉穗中秋意含。", "日暮東坡渾似畫，倚風無數水葒酣。"]'),
('039e956b-46a2-4138-b1d0-7d862d569dbc','移居  其三','丘葵','宋','宋诗','song-poetry','','[]','斷雲將雨過橋南，誰想莊門憩雨談。',64,'全唐诗/poet.song.244000.json','["斷雲將雨過橋南，誰想莊門憩雨談。", "雀喜客來喧古棘，蛙嗔人過沒深潭。", "蓮房墮粉風初歇，稻葉抽珠水尚含。", "村釀沽來薄難醉，不妨此興爲詩酣。"]'),
('c0587572-a615-49f1-950c-7847c617d401','山齋','丘葵','宋','宋诗','song-poetry','','[]','草色苔痕挾雨驕，山齋一巷似漁樵。',64,'全唐诗/poet.song.244000.json','["草色苔痕挾雨驕，山齋一巷似漁樵。", "三叉路口時時犢，一曲溪流片片橋。", "風木參差泉上廟，烟帆來往海西潮。", "飄然忽起雲間想，白鶴高飛不可招。"]'),
('edb47f06-e37f-4334-a25d-125565a6f930','和芸齋','丘葵','宋','宋诗','song-poetry','','[]','脫却簔衣下釣竿，豈無線路透玄關。',64,'全唐诗/poet.song.244000.json','["脫却簔衣下釣竿，豈無線路透玄關。", "斜風暫罷玄真去，明月來從太白攀。", "自是老懷俱惜別，偶陪清話不知還。", "夜來客枕秋聲起，磯上苔痕入夢班。"]'),
('240eb6de-2da3-4369-9c86-c0f17cb93ef7','張可大甥與古愚家兄游陽孟巖已廢而舊日之山屹然獨存有詩因次其韻','丘葵','宋','宋诗','song-poetry','','[]','笑推窗戶揖青山，茶鼎松風入耳潺。',64,'全唐诗/poet.song.244000.json','["笑推窗戶揖青山，茶鼎松風入耳潺。", "老去已知今世錯，貧來剩得此身閒。", "潄流枕石心長在，涉水穿林步已難。", "六十年來醉題壁，那知尚在白雲間。"]'),
('ed8446a9-d563-4c94-a0fe-ce5a712f3369','秋夜  其一','丘葵','宋','宋诗','song-poetry','','[]','缺月黄昏照短垣，一燈明滅尚留殘。',64,'全唐诗/poet.song.244000.json','["缺月黄昏照短垣，一燈明滅尚留殘。", "衰頹但覺風霜苦，憂患不知天地寬。", "坐想興亡成感慨，起瞻星象倍辛酸。", "凍琴弦斷書帷冷，槭槭庭梧半夜寒。"]'),
('35047563-7ae9-48da-b034-1baeb2b09dc9','秋夜  其二','丘葵','宋','宋诗','song-poetry','','[]','紛紛敗葉已辭林，四顧凄凉夜色深。',64,'全唐诗/poet.song.244000.json','["紛紛敗葉已辭林，四顧凄凉夜色深。", "月伴征人驚夢枕，風摇戌婦搗衣砧。", "失群孤雁千山影，無數寒蟲四壁音。", "滿目乾坤都是恨，頭毛白盡更愁吟。"]'),
('494735a8-0e9b-40b3-9327-a7a14a4b6266','和所盤端午韻','丘葵','宋','宋诗','song-poetry','','[]','槐夏陰中鬢已秋，天風吹夢墮江頭。',64,'全唐诗/poet.song.244000.json','["槐夏陰中鬢已秋，天風吹夢墮江頭。", "水應難洗湘纍恨，山豈能爲柳子囚。", "塵世不知幾端午，人生大抵一虛舟。", "愁來細把君詩看，壓倒當時趙倚樓。"]'),
('824f6d2d-2a51-4d22-8084-36b488a6ed4e','和所盤離相院山門納凉韻','丘葵','宋','宋诗','song-poetry','','[]','槐對青山五月寒，朝朝暮暮此看山。',64,'全唐诗/poet.song.244000.json','["槐對青山五月寒，朝朝暮暮此看山。", "風來翠瀑青松外，人在珠宮貝闕閒。", "詩客歸時文几靜，棋僧去後畫枰閒。", "禪牀一被清眠熟，夢把漁竿釣碧灣。"]'),
('56220773-74e5-4c22-a754-f7cb938a661d','和所盤自寬韻','丘葵','宋','宋诗','song-poetry','','[]','憂患薰心兩鬢絲，倚欄瘦影却斜暉。',64,'全唐诗/poet.song.244000.json','["憂患薰心兩鬢絲，倚欄瘦影却斜暉。", "凄其十載不儒服，老矣一生猶布衣。", "未信此身長坎坷，細看造物實玄微。", "五更風雨自秋至，不見蚊蠅跋扈飛。"]'),
('404215fa-4bca-401a-b717-f65f09461f5a','秋懷','丘葵','宋','宋诗','song-poetry','','[]','何處秋來在樹間，旅中寂寞欲生寒。',64,'全唐诗/poet.song.244000.json','["何處秋來在樹間，旅中寂寞欲生寒。", "篔簹粉落見秋色，薜荔青凋带老顔。", "午枕尚猶飛豹脚，曉霜久已染雞冠。", "流年偷向吟中換，老却詩人空等閒。"]'),
('0ee57002-81b4-4539-a78f-b939d2b4069a','和所盤九日','丘葵','宋','宋诗','song-poetry','','[]','石鋩如劍夢猶危，風帽橋邊且任吹。',64,'全唐诗/poet.song.244000.json','["石鋩如劍夢猶危，風帽橋邊且任吹。", "山送落暉應恨速，月臨歸路不妨遲。", "欲從此夕頹如醉，試問明年健者誰。", "一笑樽前俱是客，可堪摇動菊花期。"]'),
('0d97e226-b2e9-45a1-b1c4-78c3733bebde','和所盤闌字韻','丘葵','宋','宋诗','song-poetry','','[]','遥想山齋客夢闌，朔風吹鬢怯欄干。',64,'全唐诗/poet.song.244000.json','["遥想山齋客夢闌，朔風吹鬢怯欄干。", "黄花句裏空相憶，青鏡朝來獨自看。", "絕似東坡來海上，勝猶賈島渡桑乾。", "木奴千樹何須問，懷抱時因驥子寬。"]'),
('9cecbf74-d5a8-42e0-b336-9c7ef2834a32','元旦與可大江行','丘葵','宋','宋诗','song-poetry','','[]','日出潮回生紫烟，水光春色弄春妍。',64,'全唐诗/poet.song.244000.json','["日出潮回生紫烟，水光春色弄春妍。", "底須椒柏來爲頌，且與鷗鳬敘隔年。", "風動微波靴面皺，苔粘枯石佛頭圓。", "老來須與溪童樂，爭倚蘆花學放船。"]'),
('adeda5fe-319e-4f6b-979d-39164070a836','與可大水頭閑望','丘葵','宋','宋诗','song-poetry','','[]','曖入紗巾淡淡風，倚樓客思話無窮。',64,'全唐诗/poet.song.244000.json','["曖入紗巾淡淡風，倚樓客思話無窮。", "前山倒影摇春水，野火飛烟入暮空。", "無數舟人相爾汝，一群沙鳥自西東。", "江流不碍鐘聲度，和雨收來八句中。"]'),
('fbefaeb6-8216-446e-8659-323346536403','過方廣寺','丘葵','宋','宋诗','song-poetry','','[]','故人昔日此留題，因入招提爲覓詩。',64,'全唐诗/poet.song.244000.json','["故人昔日此留題，因入招提爲覓詩。", "石鼓長存僧屢換，窟泉尚在馬安之。", "風簷落葉仍唐檜，苔壁生塵且宋碑。", "蝴蝶不知春已去，過牆猶顧舊花枝。"]'),
('01dfc134-460d-4c2d-a184-b8e43e75a6f6','呈古直','丘葵','宋','宋诗','song-poetry','','[]','芹泮西風寂寞濱，相逢不作白頭新。',64,'全唐诗/poet.song.244000.json','["芹泮西風寂寞濱，相逢不作白頭新。", "人知叔向古遺直，誰識堯夫今逸民。", "自古文章差底病，歷觀賢聖莫非貧。", "老來安養浩然氣，吾輩安能俯仰人。"]'),
('6fae2e2f-bcc8-41c5-8d4a-2fb7ff15f918','呈張尚友','丘葵','宋','宋诗','song-poetry','','[]','秋風匹馬柳江邊，芹泮相逢意浩然。',64,'全唐诗/poet.song.244000.json','["秋風匹馬柳江邊，芹泮相逢意浩然。", "吏部文章懸日月，子長史記在山川。", "輸君何啻百籌上，期我曾言千載前。", "造物無情吾輩老，後生誰可囑遺編。"]'),
('03bafd3b-2a4e-4d6e-8670-3fdf1707aa07','自修','丘葵','宋','宋诗','song-poetry','','[]','昔髧兩鬢今白頭，肯將胸次著閒愁。',64,'全唐诗/poet.song.244000.json','["昔髧兩鬢今白頭，肯將胸次著閒愁。", "無邊風月隨宜樂，有分江山取次遊。", "但得捫心無愧怍，庶幾省己少愆尤。", "榮枯壽夭無爲二，未死之前盍自修。"]'),
('a529283d-0d43-4075-b9c0-6203368fc790','重九','丘葵','宋','宋诗','song-poetry','','[]','病餘惟有骨崚嶒，節物催人祇自驚。',64,'全唐诗/poet.song.244000.json','["病餘惟有骨崚嶒，節物催人祇自驚。", "肩比寒山爲獨聳，心將秋水覺雙清。", "正冠落帽俱兒戲，採菊囊萸不老成。", "寂寞空齋捲書坐，欲持盃酒爲誰傾。"]'),
('23b19011-1b14-45eb-94a9-e146a4322894','晚行書所見','丘葵','宋','宋诗','song-poetry','','[]','夕陽半落紅猶在，寒月初升白未勻。',64,'全唐诗/poet.song.244000.json','["夕陽半落紅猶在，寒月初升白未勻。", "流水孤村天欲暮，頹簷敗壁野無人。", "雀啣遺芥營巢急，蛛繹新絲織網頻。", "欲問前朝無故老，髑髏落地路荆榛。"]'),
('145595e1-0f26-4e38-b126-59cd2887f118','感遇','丘葵','宋','宋诗','song-poetry','','[]','本是畏人嫌我真，何人使我入城闉。',64,'全唐诗/poet.song.244000.json','["本是畏人嫌我真，何人使我入城闉。", "客中誰問張仲蔚，夜半有呼祁孔賓。", "萬象不離心內易，一私壞盡世間人。", "半生說過行無寸，石火光中寄此身。"]'),
('cd1e3a43-0dc5-4431-9eed-bf313c230f9c','貧病','丘葵','宋','宋诗','song-poetry','','[]','貧似山僧瘦似猿，病軀只合老山村。',64,'全唐诗/poet.song.244000.json','["貧似山僧瘦似猿，病軀只合老山村。", "空床鼿卼無氈卧，破褐繿縿有虱捫。", "作甫里翁垂釣艇，學猗玕子飲漥樽。", "前修追慕吾何敢，孤負西埔矩老言。"]'),
('aa6a2302-d964-4844-9cae-b95cb3b8364d','呂所盤已回故居月餘日忽憶舊時與遊因約再訪','丘葵','宋','宋诗','song-poetry','','[]','匆匆別后又秋凉，佳句遥知塞錦囊。',64,'全唐诗/poet.song.244000.json','["匆匆別后又秋凉，佳句遥知塞錦囊。", "聞道拾遺流落久，歸尋小隠釣遊鄉。", "舊時鄰曲渾如夢，此日江東欲斷腸。", "擬待梅花携斗酒，訪君船泊小溪傍。"]'),
('8d8c3689-3b93-4be0-be02-88b067452a5a','東歸擬再訪呂所盤舟便不果盤有詩因次韻以謝','丘葵','宋','宋诗','song-poetry','','[]','對酒殷勤問後期，出門一步便相思。',64,'全唐诗/poet.song.244000.json','["對酒殷勤問後期，出門一步便相思。", "自從剡曲回舟後，長憶巴山聽雨時。", "鶴髮無成應念我，貂裘已敝欲從誰。", "歸途不向盤中過，却被清泉笑惡詩。"]'),
('548e61de-5dc4-4c68-a595-e487193f2fc2','寄肯體','丘葵','宋','宋诗','song-poetry','','[]','三年雲卧一身閒，惟有君來蕭寺間。',64,'全唐诗/poet.song.244000.json','["三年雲卧一身閒，惟有君來蕭寺間。", "既是君平爲世棄，不妨巢父掉頭還。", "平生學道魚千里，晚歲參禪豹一班。", "惟有聖賢真實地，吾儕努力莫辭難。"]'),
('c6da0480-e9c5-4cff-9da2-5b54402738f0','八十歲吟','丘葵','宋','宋诗','song-poetry','','[]','自愧身無濟世才，茅齋高卧白雲隈。',64,'全唐诗/poet.song.244000.json','["自愧身無濟世才，茅齋高卧白雲隈。", "堂堂玉立窗前竹，疊疊前鋪砌上苔。", "白鳥去邊春日落，青山斷處晚潮來。", "逢人不必言時事，共把情懷對酒開。"]'),
('5f9c4902-06d7-42a8-be3d-6b7daa5c5b3e','示兒','丘葵','宋','宋诗','song-poetry','','[]','喫緊爲人毋自欺，吾猶失學况吾兒。',64,'全唐诗/poet.song.244000.json','["喫緊爲人毋自欺，吾猶失學况吾兒。", "人誰無過過須改，道不遠人人莫知。", "一定萬牛拖不動，少差駟馬亦難追。", "如今老去空惆悵，八十年前盡背馳。"]'),
('4e4beef5-fa26-4e1f-8014-8f5e97e9112e','八十四歲吟','丘葵','宋','宋诗','song-poetry','','[]','百年尚有一十六，天不窮人人自窮。',64,'全唐诗/poet.song.244000.json','["百年尚有一十六，天不窮人人自窮。", "未解寡尤并寡悔，若爲知至又知終。", "如真可死何妨死，欲養不中那得中。", "無可奈何委諸命，狂瀾終久必須東。"]'),
('0d1848a4-53d6-4388-86ee-abb3368da82a','求約','丘葵','宋','宋诗','song-poetry','','[]','求約未能休厭繁，每於得處自難言。',64,'全唐诗/poet.song.244000.json','["求約未能休厭繁，每於得處自難言。", "書曾過眼平心看，道不依形觸目存。", "木本草根如有見，山巔水際盡逢源。", "可憐日月惟空過，休聽鐘聲送黄昏。"]'),
('eaf2b3cb-e581-49ce-93ee-423662eb6051','一中','丘葵','宋','宋诗','song-poetry','','[]','莫把三才別立根，此身亦自一中分。',64,'全唐诗/poet.song.244000.json','["莫把三才別立根，此身亦自一中分。", "四時環繞天包地，萬片捲舒山出雲。", "道在靈臺常潑潑，氣歸元海自沄沄。", "百年保合太和內，老學無成恐有聞。"]'),
('bd5439b2-7b9a-4661-a130-fafb2678d7bc','白露日獨立','丘葵','宋','宋诗','song-poetry','','[]','西風吹我鬢鬅鬙，獨立庭中影隨形。',64,'全唐诗/poet.song.244000.json','["西風吹我鬢鬅鬙，獨立庭中影隨形。", "一歲露從今夜白，百年眼對老天青。", "經秋不脫無多樹，近月能明有幾星。", "惆悵前修人去盡，後生誰可囑遺經。"]'),
('330e5c52-e992-4228-92a2-5b8db33b195b','磊落','丘葵','宋','宋诗','song-poetry','','[]','磊落襟懷人不知，回頭堪嘆亦堪悲。',64,'全唐诗/poet.song.244000.json','["磊落襟懷人不知，回頭堪嘆亦堪悲。", "盃殘炙冷窮工部，齒豁頭童老退之。", "十事有九不如意，百年踰八欲何爲。", "早知人世暗如漆，只合竈間食蛤蜊。"]'),
('351d7686-b604-403f-93d7-982b500dd9fb','清晝','丘葵','宋','宋诗','song-poetry','','[]','誰信茅茨即玉堂，閒來清晝似宵長。',64,'全唐诗/poet.song.244000.json','["誰信茅茨即玉堂，閒來清晝似宵長。", "二儀升降太虛內，一靜消磨萬意忙。", "忿欲俱空心自正，行持無力夢猶狂。", "可曾濯足滄江水，飛上雲間千仞岡。"]'),
('460cb26a-d4e7-4c40-baed-fbe56b0d9c11','用伯恭次信兒韻因以示之','丘葵','宋','宋诗','song-poetry','','[]','老至如斯更不愆，此生自斷總由天。',64,'全唐诗/poet.song.244000.json','["老至如斯更不愆，此生自斷總由天。", "丈夫事到蓋棺定，男子生隨墮地緣。", "誤讀銀車知昶拙，點成珠唾頼勤賢。", "孤槎欲泛千尋海，常望龍驤萬斛牽。"]'),
('b9e5f916-da38-4e56-a382-a82b23a9a6f1','病中作','丘葵','宋','宋诗','song-poetry','','[]','獨坐茅簷靜養疴，亦知來日苦無多。',64,'全唐诗/poet.song.244000.json','["獨坐茅簷靜養疴，亦知來日苦無多。", "此心不動窮無鬼，元氣將衰病有魔。", "嘆老嗟卑非我事，貪生怛化欲如何。", "平生不爲浮屠惑，自此幢峰土一窩。"]'),
('90e650bf-2c27-47bd-9572-abb143f43de8','養疴','丘葵','宋','宋诗','song-poetry','','[]','八尺空牀坐養疴，老來真是病維摩。',64,'全唐诗/poet.song.244000.json','["八尺空牀坐養疴，老來真是病維摩。", "虛皇大道無爲爾，造物小兒如我何。", "許大乾坤無處著，這些軀殻累人多。", "何當飛入虛空裏，骨肉收歸土一窩。"]'),
('062e6518-ec19-4925-94c0-6877b5a37752','跋信中隠秋江捕魚圖','丘葵','宋','宋诗','song-poetry','','[]','逸興寄滄洲，高風落木秋。',24,'全唐诗/poet.song.244000.json','["逸興寄滄洲，高風落木秋。", "欲携我蓑笠，渡口上漁舟。"]'),
('9fd3fd3d-3af9-4439-9fba-5708a7c7f6fe','晚行書所見','丘葵','宋','宋诗','song-poetry','','[]','山澗雨初收，涓涓水亂流。',24,'全唐诗/poet.song.244000.json','["山澗雨初收，涓涓水亂流。", "樹根一片石，童子坐牽牛。"]'),
('c4e7563b-91d2-4c61-9a93-a7c0967067e3','梅影','丘葵','宋','宋诗','song-poetry','','[]','山空年歲晚，老氣寒崢嶸。',24,'全唐诗/poet.song.244000.json','["山空年歲晚，老氣寒崢嶸。", "耿耿霜月夜，相看直到明。"]'),
('0a679634-df30-4ec4-ab34-365270a85ace','秋夜有感','丘葵','宋','宋诗','song-poetry','','[]','萬斛秋愁强自寬，夜深風露伴孤寒。',32,'全唐诗/poet.song.244000.json','["萬斛秋愁强自寬，夜深風露伴孤寒。", "可憐萬里長空月，只得窗前一片看。"]'),
('d0f37164-f727-4829-85a3-8bdc74db4c6d','臘月二十九日陳萬石石室呂潜心三兄相訪夜坐分韻得年字','丘葵','宋','宋诗','song-poetry','','[]','二十年前舊師友，一燈相對坐談玄。',32,'全唐诗/poet.song.244000.json','["二十年前舊師友，一燈相對坐談玄。", "爐香茗椀不須睡，惟有今宵是舊年。"]'),
('6b0f8324-893e-48bf-9a5a-4bb70f890bf3','挽心泉蒲處士  其一','丘葵','宋','宋诗','song-poetry','','[]','把釣秋風辱贈詩，傷心無路送靈輀。',32,'全唐诗/poet.song.244000.json','["把釣秋風辱贈詩，傷心無路送靈輀。", "欲書誄語應難盡，獨倚寒梅照石漪。"]'),
('86e2f219-5902-4e32-8402-73079a9ae9bf','挽心泉蒲處士  其二','丘葵','宋','宋诗','song-poetry','','[]','欲持雞絮立墳前，俗了青霞頂上仙。',32,'全唐诗/poet.song.244000.json','["欲持雞絮立墳前，俗了青霞頂上仙。", "只合化爲溪畔鷺，乘風飛去弄清泉。"]'),
('d2fd89a1-8b91-4b74-affc-28aa7112d43d','次歐陽少逸韻呈雪庭禪師  其一','丘葵','宋','宋诗','song-poetry','','[]','蘋婆影鏤日華明，照見枝頭果已成。',32,'全唐诗/poet.song.244000.json','["蘋婆影鏤日華明，照見枝頭果已成。", "却是南風有吟思，時將萬葉作秋聲。"]'),
('3f54b0c6-5af5-457a-ba95-6bbb3914a507','次歐陽少逸韻呈雪庭禪師  其二','丘葵','宋','宋诗','song-poetry','','[]','吟得秋聲滿院凉，不知六月有驕陽。',32,'全唐诗/poet.song.244000.json','["吟得秋聲滿院凉，不知六月有驕陽。", "禪心已是空諸相，無奈瓶花故故香。"]'),
('ee2a31fd-865c-4016-8606-ba04430bb7e8','次歐陽少逸韻呈雪庭禪師  其三','丘葵','宋','宋诗','song-poetry','','[]','瓶花故故透禪房，師自無心花自香。',32,'全唐诗/poet.song.244000.json','["瓶花故故透禪房，師自無心花自香。", "客散夜深歸定裏，白生虛室月無光。"]'),
('f1ed3e82-b4d6-4706-acd6-30b60ad66622','北山聞鐘亭','丘葵','宋','宋诗','song-poetry','','[]','曉來草木自澄鮮，不到山中又五年。',32,'全唐诗/poet.song.244000.json','["曉來草木自澄鮮，不到山中又五年。", "惆悵聞鐘人不見，空餘古木鎖寒烟。"]'),
('d76f5f98-ea22-4392-b3e9-41022c604abf','遊碧霄石鎸一壽字今七十二年','丘葵','宋','宋诗','song-poetry','','[]','當時石上誰爲鎸，亭已荒蕪字儼然。',32,'全唐诗/poet.song.244000.json','["當時石上誰爲鎸，亭已荒蕪字儼然。", "七十二年幾陵谷，道人曾共字同年。"]'),
('9cf85696-b9b3-4df3-b324-3094df469826','永寧庵','丘葵','宋','宋诗','song-poetry','','[]','路入永寧方午陰，禪師聊復坐沉吟。',32,'全唐诗/poet.song.244000.json','["路入永寧方午陰，禪師聊復坐沉吟。", "欲將門外葫蘆水，倒作田間三日霖。"]'),
('de329349-291a-41b2-9b8c-317f8ff4db07','新晴','丘葵','宋','宋诗','song-poetry','','[]','新晴登㟝嶁，欣此凍初解。',48,'全唐诗/poet.song.244000.json','["新晴登㟝嶁，欣此凍初解。", "春風入條肄，枯枿依然在。", "有美北山薇，良苗正堪採。", "我欲携短筐，悠悠隔滄海。"]'),
('83e492b8-282a-4c60-b53d-77e0888d27b7','仰高堂外看山','丘葵','宋','宋诗','song-poetry','','[]','半生勞仰止，今日忽墮前。',72,'全唐诗/poet.song.244000.json','["半生勞仰止，今日忽墮前。", "如忘形骸友，相對亦屹然。", "此心有全體，動靜無塵緣。", "遥睇層層碧，羣仙室其巔。", "我欲往從之，於道恐未然。", "但當安所止，萬物同此天。"]'),
('15cf906d-44b5-4f4e-98fa-ffcb136b5459','煮粥','丘葵','宋','宋诗','song-poetry','','[]','清晨掃松葉，旋復烘于煁。',48,'全唐诗/poet.song.244000.json','["清晨掃松葉，旋復烘于煁。", "汲井手自淅，咄嗟香滿鬵。", "母子共一飽，茅簷樂愔愔。", "雖無滫瀡奉，庶不愧此心。"]'),
('851d7ae3-ce4f-4771-8582-d2945693bd8e','同景仁芝山賞梅','丘葵','宋','宋诗','song-poetry','','[]','西風殺羣卉，麋鹿覺悽愴。',60,'全唐诗/poet.song.244000.json','["西風殺羣卉，麋鹿覺悽愴。", "野菊亦憔悴，蕭條不堪賞。", "主人庵中梅，的皪爲誰放。", "當茲肅霜月，數枝春盎盎。", "真如得道人，形槁神獨王。"]'),
('420d175c-7e4c-46e2-9416-c38d37f29c42','閉戶','丘葵','宋','宋诗','song-poetry','','[]','自我來茲泮，閉戶交遊絕。',48,'全唐诗/poet.song.244000.json','["自我來茲泮，閉戶交遊絕。", "經生一二輩，長庚伴殘月。", "芹藻自青青，誰與共採擷。", "唯於潑潑處，見得源頭活。"]'),
('8d4437fc-d0f7-4a71-b4fb-0461a6b486f8','三月三十日','丘葵','宋','宋诗','song-poetry','','[]','盎盎天地春，萬物日和煦。',120,'全唐诗/poet.song.244000.json','["盎盎天地春，萬物日和煦。", "云胡生五穀，不若草木數。", "天地一小變，六龍不行雨。", "東皇詎忍歸，田間已焦土。", "□□□□人，書生空自愁。", "饑死者不恨，特爲蒼生憂。", "我願呼東皇，爲我呼屏翳。", "沛爲三日霖，枯苗有生意。", "皇天青蕩蕩，無繇訴衷情。", "空憐汝布穀，辛苦催人耕。"]'),
('0b519bde-79bb-4520-b63e-d915b419e2de','懷古愚兄  其一','丘葵','宋','宋诗','song-poetry','','[]','紫帽之峰兮高且巍，白雲一片兮空依依。',36,'全唐诗/poet.song.244000.json','["紫帽之峰兮高且巍，白雲一片兮空依依。", "我有兄兮在海湄，三月不見兮使我心悲。"]'),
('c7ed9d02-c75a-4fbb-b0bd-d64744d05d3b','懷古愚兄  其二','丘葵','宋','宋诗','song-poetry','','[]','紫帽之峰兮高且崷，白雲一片兮空悠悠。',36,'全唐诗/poet.song.244000.json','["紫帽之峰兮高且崷，白雲一片兮空悠悠。", "我有兄兮在海陬，三月不見兮使我心憂。"]'),
('c890f9b8-8634-4978-9d89-9f12c2ad5fb1','懷古愚兄  其三','丘葵','宋','宋诗','song-poetry','','[]','有荷薦香，有竹薦凉。',20,'全唐诗/poet.song.244000.json','["有荷薦香，有竹薦凉。", "歸哉歸哉，一觥對床。"]'),
('8d3acb80-5b8d-4091-ae9b-7ff1a7cc8100','讀元次山詩有感而作','丘葵','宋','宋诗','song-poetry','','[]','民病未蘇息，誰爲元道州。',48,'全唐诗/poet.song.244000.json','["民病未蘇息，誰爲元道州。", "爭趨熱翕翕，不念冷颼颼。", "摧剝先蟲戶，差科及釣舟。", "君門千萬里，欲往訴無由。"]'),
('0a8f5025-6b00-4abf-8834-4c2d194a9918','舟中避難','丘葵','宋','宋诗','song-poetry','','[]','拏舟來避難，別我釣魚磯。',48,'全唐诗/poet.song.244000.json','["拏舟來避難，別我釣魚磯。", "帆卸遮春雨，衣濡曬落暉。", "南師聞韃走，北馬逐人飛。", "見說漳橋斷，鑾輿曷日歸。"]'),
('08964835-e42a-4944-b2ad-1fa8731a987e','日入','丘葵','宋','宋诗','song-poetry','','[]','日入川原暝，風悲草木枯。',48,'全唐诗/poet.song.244000.json','["日入川原暝，風悲草木枯。", "時逢迂孔氏，我自哭唐衢。", "市有虎求食，村無雞引雛。", "乾坤空納納，何處著吾軀。"]'),
('32ab5687-75a7-4f1c-9194-190611139282','到郡城憶江釣','丘葵','宋','宋诗','song-poetry','','[]','誰使入州府，被人嫌我真。',48,'全唐诗/poet.song.244000.json','["誰使入州府，被人嫌我真。", "未歸江上釣，且作夢中人。", "一片滄浪石，百年泡幻身。", "知心惟白鷺，相憶伴經綸。"]'),
('7c159c59-44c1-4ed5-ae36-4ffc64d1ab4c','六月寓章法寺','丘葵','宋','宋诗','song-poetry','','[]','暝色入招提，昏鴉已不啼。',48,'全唐诗/poet.song.244000.json','["暝色入招提，昏鴉已不啼。", "諸僧空院出，老子獨山棲。", "堂面無人北，天形盡日西。", "寂寥應不恨，吾道與時睽。"]'),
('965eae31-bb7a-42ac-8d68-0db46e154144','瑞光亭','丘葵','宋','宋诗','song-poetry','','[]','昔聞石幢寺，今見瑞光亭。',48,'全唐诗/poet.song.244000.json','["昔聞石幢寺，今見瑞光亭。", "一水東南碧，四榕冬夏青。", "往來多俗子，老病抱遺經。", "親冢招提北，回頭涕泗零。"]'),
('f892d3bc-148f-4df2-a2b9-126548e2db2d','贈富公','丘葵','宋','宋诗','song-poetry','','[]','師年過七十，萬事總無心。',48,'全唐诗/poet.song.244000.json','["師年過七十，萬事總無心。", "猿鳥窺禪性，魚龍避梵音。", "煙消香篆冷，霜入鬢根深。", "手種庵前樹，蒼蒼十丈陰。"]'),
('cdd2119d-4539-497e-9c60-beb549428373','別城中親友','丘葵','宋','宋诗','song-poetry','','[]','不堪離亂後，重別舊交遊。',48,'全唐诗/poet.song.244000.json','["不堪離亂後，重別舊交遊。", "到處無青眼，歸家空白頭。", "風霜秋一葉，山水暮多愁。", "後會知何日，臨溪淚欲流。"]'),
('91fcc4e0-2a11-49d5-9185-9a1c6991448c','贈雲岫上人','丘葵','宋','宋诗','song-poetry','','[]','諸生多晚出，一老獨高年。',48,'全唐诗/poet.song.244000.json','["諸生多晚出，一老獨高年。", "月照遺經匣，雲生破衲褰。", "苔深埋屐齒，屋老带松煙。", "何日塵氛斷，從師此話禪。"]'),
('37c70642-0b97-49db-9830-6eb8582e3fce','送誼上人歸城','丘葵','宋','宋诗','song-poetry','','[]','恰是聞師到，持筇又欲歸。',48,'全唐诗/poet.song.244000.json','["恰是聞師到，持筇又欲歸。", "去雲黏木屐，飄葉泊禪衣。", "不敢生離思，應愁損道機。", "故人如見問，爲說志漁磯。"]'),
('6b73f82f-c938-4b56-bbcd-b25767229169','夜意','丘葵','宋','宋诗','song-poetry','','[]','茅齋人語寂，清坐獨巑岏。',48,'全唐诗/poet.song.244000.json','["茅齋人語寂，清坐獨巑岏。", "有興憑詩遣，無聊把劍看。", "香殘金鴨冷，膏盡玉蟲寒。", "出見庭無月，方知夜色闌。"]'),
('c194c3d2-8f83-4721-a0d9-b02b59236f1f','曉意','丘葵','宋','宋诗','song-poetry','','[]','鄰窗雞唱曉，客路馬嘶風。',48,'全唐诗/poet.song.244000.json','["鄰窗雞唱曉，客路馬嘶風。", "夜色鍾聲外，晨光角韻中。", "蟾歸曳殘白，烏出浴新紅。", "一點清明意，那無保養功。"]'),
('7b59c20b-e2c0-4e73-96a7-84bdc8fc7546','孤客','丘葵','宋','宋诗','song-poetry','','[]','綠綠竹生笋，黄黄菜又花。',48,'全唐诗/poet.song.244000.json','["綠綠竹生笋，黄黄菜又花。", "一年今已夏，孤客未還家。", "夜對青燈減，朝看白髮加。", "由來事筆硯，不若藝桑麻。"]'),
('05caa8d2-334b-4b29-9e52-1b897cc2e00f','雨後憶家','丘葵','宋','宋诗','song-poetry','','[]','客裏詩書債，人間骨肉情。',48,'全唐诗/poet.song.244000.json','["客裏詩書債，人間骨肉情。", "一春不相見，四月又還經。", "梅雨年年事，田禽夜夜聲。", "直思到蒲節，方得侍親庭。"]'),
('efd58a42-9b8e-4531-af91-af64c5646efa','歸侍','丘葵','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','村莊一罇酒，誰與語悲辛。',48,'全唐诗/poet.song.244000.json','["村莊一罇酒，誰與語悲辛。", "衿佩空相負，詩書不救貧。", "天寒負米客，日暮倚門人。", "遥睇長江水，西風猶愴神。"]'),
('62f86802-9fdc-433d-8824-7bcf323d080b','病中','丘葵','宋','宋诗','song-poetry','','[]','數日喉何嗄，三年肺未蘇。',48,'全唐诗/poet.song.244000.json','["數日喉何嗄，三年肺未蘇。", "自知愁不禁，誰復問何如。", "病體仍冬夜，山莊獨老夫。", "恐傷阿㜷意，不敢寄家書。"]'),
('243b313f-fdaf-4e1b-a560-c123a7b7f50d','龍湖道中','丘葵','宋','宋诗','song-poetry','','[]','冬行緣底意，倚杖陟高岡。',48,'全唐诗/poet.song.244000.json','["冬行緣底意，倚杖陟高岡。", "日色带霜淡，風聲過海狂。", "林鴉山外黑，野菜麥中黄。", "臘月明朝是，棲棲尚異鄉。"]'),
('70e2d462-cd1a-462e-875a-ea5fceb5214b','寄曾子方','丘葵','宋','宋诗','song-poetry','','[]','別來俱不飲，相憶若爲情。',48,'全唐诗/poet.song.244000.json','["別來俱不飲，相憶若爲情。", "交態忘貧富，相知似弟兄。", "君殊非夙昔，予亦負平生。", "惟有子城月，年年是舊盟。"]'),
('ecaa3591-3385-4d74-ba90-a3464009057f','題可翁塔','丘葵','宋','宋诗','song-poetry','','[]','至人埋骨地，草木總皆玄。',48,'全唐诗/poet.song.244000.json','["至人埋骨地，草木總皆玄。", "未臘梅先覺，無風竹亦禪。", "燈緣千載燄，名共四松傳。", "舊日經行處，瓶盂常儼然。"]'),
('732e06af-a151-4433-a05f-f177a05702dd','哭矩齋先生','丘葵','宋','宋诗','song-poetry','','[]','早悟官爲祟，晚將家付兒。',48,'全唐诗/poet.song.244000.json','["早悟官爲祟，晚將家付兒。", "公今成佛去，僕尚是人猗。", "柿葉收遺墨，梅花憶贈詩。", "自嫌聞道晚，有淚哭先師。"]'),
('adca30ae-3de8-4388-8f10-6153345f3e93','和北城友人','丘葵','宋','宋诗','song-poetry','','[]','桐邊一葉地，相望立秋風。',48,'全唐诗/poet.song.244000.json','["桐邊一葉地，相望立秋風。", "昔別已三載，今來成兩翁。", "醒初無異醉，窮亦豈殊通。", "却笑甲辰一，雌雄自不同。"]'),
('e81fa311-ea17-4101-ac08-445ed47fa684','遊龍湖庵','丘葵','宋','宋诗','song-poetry','','[]','一路野花開，春陰滿樹苔。',48,'全唐诗/poet.song.244000.json','["一路野花開，春陰滿樹苔。", "舊時僧已去，前度客重來。", "浮世年年變，塵心事事灰。", "跏趺清晝永，玄奘壁間回。"]'),
('f745bfc6-7a8b-4d0e-a5e1-b2faa27b7c69','和呂所盤韻','丘葵','宋','宋诗','song-poetry','','[]','春豈關儂去，愁緣老易生。',48,'全唐诗/poet.song.244000.json','["春豈關儂去，愁緣老易生。", "一村俄綠暗，數日又朱明。", "細切銀絲鱠，新嘗玉版羹。", "便令聞杜宇，自不動鄉情。"]'),
('2ef1f80e-8c0f-4b06-8774-d4c8d4a67174','支筇','丘葵','宋','宋诗','song-poetry','','[]','天乎多往事，老矣負初心。',48,'全唐诗/poet.song.244000.json','["天乎多往事，老矣負初心。", "病骨瘦又瘦，愁詩吟復吟。", "一生空碌碌，萬綠自森森。", "多少關情處，支筇古樹陰。"]'),
('080548fb-f811-40d7-a4f8-cee085219b15','雨後有便价寄所盤','丘葵','宋','宋诗','song-poetry','','[]','雨中正相憶，偶爾有來鴻。',48,'全唐诗/poet.song.244000.json','["雨中正相憶，偶爾有來鴻。", "清况今何苦，新吟想漸工。", "近聞惠連病，似與長卿同。", "何日蒼榕下，開筵水面紅。"]'),
('a9ab653f-b7a6-4293-953d-7e0e6f9cf9f7','宿鏡山欲訪之壽忽聞東浯思仲至約爲南山之遊不果','丘葵','宋','宋诗','song-poetry','','[]','鏡山欲相訪，馬首已之東。',48,'全唐诗/poet.song.244000.json','["鏡山欲相訪，馬首已之東。", "常日對衿佩，此行如燕鴻。", "將歸逢所與，有約竟成空。", "若到齋中日，爲予傳主翁。"]'),
('cfd0b924-e0dd-43ee-b7c7-613a0507cb23','書陳氏小軒壁','丘葵','宋','宋诗','song-poetry','','[]','一榻自徜徉，悠然古意長。',48,'全唐诗/poet.song.244000.json','["一榻自徜徉，悠然古意長。", "地幽如佛舍，軒小似船房。", "萱草依堂綠，荆花夾樹香。", "我來訪幽隠，話裏雨聲凉。"]'),
('fc9ae776-42ca-4563-9851-dc64f4133962','田間行樂','丘葵','宋','宋诗','song-poetry','','[]','一年又朱夏，殘生如白鷗。',48,'全唐诗/poet.song.244000.json','["一年又朱夏，殘生如白鷗。", "未須愁熱去，且得及清遊。", "數點雨初下，千溝水盡流。", "誰家田萬頃，綠到海西頭。"]'),
('1364764b-7983-426d-8ad7-aae17df635f5','春日閒遊過石所山','丘葵','宋','宋诗','song-poetry','','[]','盎盎春流水，微微風動蘋。',48,'全唐诗/poet.song.244000.json','["盎盎春流水，微微風動蘋。", "江山一片石，童冠兩三人。", "落魄從渠笑，逍遥得我真。", "百年渾是客，一月幾佳晨。"]'),
('0caf8fa5-d9ab-4b43-a2d1-b66cc4e2e142','初夏','丘葵','宋','宋诗','song-poetry','','[]','一信楝花風，一年春事空。',48,'全唐诗/poet.song.244000.json','["一信楝花風，一年春事空。", "池荷還揭揭，櫻笋又匆匆。", "空嘆時光換，誰知造化工。", "盡將枝上色，并作石榴紅。"]'),
('de30dde1-3bb2-40a4-8aee-59c096df1b73','次長卿韻','丘葵','宋','宋诗','song-poetry','','[]','秋盡始相見，宵殘即語離。',48,'全唐诗/poet.song.244000.json','["秋盡始相見，宵殘即語離。", "將歸悲宋玉，不飲愧袁絲。", "送遠意未愜，思家興頗隨。", "可憐鏡山夜，未與小盤期。"]'),
('b4c3238f-4e69-43e0-9151-6850203fd703','次韻長卿仍招爲桐下之遊','丘葵','宋','宋诗','song-poetry','','[]','老懷原寂寞，非子竟誰傾。',48,'全唐诗/poet.song.244000.json','["老懷原寂寞，非子竟誰傾。", "去矣無多日，緬然相與情。", "雲山留共往，風雪渺孤征。", "更解同行否，無爲歲暮驚。"]'),
('892818f8-a60a-487d-a1c3-78d8c7afe544','雨中宿章法院','丘葵','宋','宋诗','song-poetry','','[]','瀟瀟一江雨，凉氣入山扉。',48,'全唐诗/poet.song.244000.json','["瀟瀟一江雨，凉氣入山扉。", "離舍本不遠，連朝亦忘歸。", "紫荆成子落，黑蟻化蛾飛。", "看盡浮生事，終輸破衲衣。"]'),
('9eda32e2-9469-4b3a-b320-eeffe35d76f8','呂之壽詩到仍用前韻約爲五峰之游同訪老人','丘葵','宋','宋诗','song-poetry','','[]','客中枉佳句，三復喜還悲。',48,'全唐诗/poet.song.244000.json','["客中枉佳句，三復喜還悲。", "冉冉歲暮矣，悠悠思何之。", "桐下不共往，梅花預作期。", "地爐風雪夜，同訪五峰緇。"]'),
('3e7f3a2b-bf70-4d45-9c77-80836fc312f3','用前韻寄幾仲','丘葵','宋','宋诗','song-poetry','','[]','丈夫語意豁，不爲別腸悲。',48,'全唐诗/poet.song.244000.json','["丈夫語意豁，不爲別腸悲。", "有酒再醑我，緣君一中之。", "顧此風霜景，闊哉牛女期。", "梅花山館裏，誰問敝衣緇。"]'),
('5cb5e111-7fe4-428e-85b9-e42057f76331','和顔北城梅花韻','丘葵','宋','宋诗','song-poetry','','[]','白髮寒叢裏，疏枝的爍明。',48,'全唐诗/poet.song.244000.json','["白髮寒叢裏，疏枝的爍明。", "風霜半夜後，南北一時晴。", "冷淡吟邊景，啁嘈夢裏聲。", "園中幾許樹，獨汝最關情。"]'),
('85e7a50d-fb97-474b-a7a2-8bc4c51af516','離相院暫憩','丘葵','宋','宋诗','song-poetry','','[]','一別已五載，重來得舊朋。',48,'全唐诗/poet.song.244000.json','["一別已五載，重來得舊朋。", "秋風多敗葉，童行半爲僧。", "暫憩亦云好，長遊愧未能。", "前山久相識，爲我碧崚嶒。"]'),
('535edde8-40b3-4e66-aeaa-94264a0f9116','過李氏山房清坐對雨','丘葵','宋','宋诗','song-poetry','','[]','千林同霢霂，一室淡虛明。',48,'全唐诗/poet.song.244000.json','["千林同霢霂，一室淡虛明。", "餘潤浮窗眼，輕寒入鳥聲。", "紛紛度隴白，亹亹逼人清。", "相對焚香坐，油然道氣生。"]'),
('8f698826-03de-475e-9338-234277ecae54','對竹','丘葵','宋','宋诗','song-poetry','','[]','此君無媚色，耿耿合予衷。',48,'全唐诗/poet.song.244000.json','["此君無媚色，耿耿合予衷。", "外直形容瘦，中虛忿慾空。", "炎凉多變態，瀟瀟獨清風。", "幸免斧斤患，蒼然保令終。"]'),
('20da2fa2-13b2-4f4e-8c37-0c41c7ee13f9','新月','丘葵','宋','宋诗','song-poetry','','[]','斗柄猶未酉，明生已自庚。',48,'全唐诗/poet.song.244000.json','["斗柄猶未酉，明生已自庚。", "月光本端正，人見有虧盈。", "寂感此太極，炎凉彼世情。", "徘徊花影下，獨自掩柴扃。"]'),
('39f66c29-bd64-44af-bbdd-e980c8f3e50f','夜誦','丘葵','宋','宋诗','song-poetry','','[]','夜誦琅琅罷，山齋人跡無。',48,'全唐诗/poet.song.244000.json','["夜誦琅琅罷，山齋人跡無。", "蟲聲助嘆息，月影伴清癯。", "黄卷十年子，青燈一腐儒。", "時危無用處，我自笑非夫。"]'),
('172bcefe-14cb-4154-b846-d4f698c92c63','浪出','丘葵','宋','宋诗','song-poetry','','[]','浪出鬼揶揄，歸來失故吾。',48,'全唐诗/poet.song.244000.json','["浪出鬼揶揄，歸來失故吾。", "庭空榕落子，人靜鳥呼雛。", "潮退石自出，天高日正晡。", "寥寥誰與語，懷古一長吁。"]'),
('3b08bc68-483f-4a01-ab10-e0baf159423a','哭高氏妹','丘葵','宋','宋诗','song-poetry','','[]','寒月照幽閨，眉多客裏齊。',48,'全唐诗/poet.song.244000.json','["寒月照幽閨，眉多客裏齊。", "飄零杜氏妹，隠約伯鸞妻。", "烏啄有新哺，鳳飛無故棲。", "近聞猶子說，憶汝萬行啼。"]'),
('242698f5-5c27-40d1-a5cc-d3364865f7b8','錢侯寺','丘葵','宋','宋诗','song-poetry','','[]','福唐錢氏子，爵命古諸侯。',48,'全唐诗/poet.song.244000.json','["福唐錢氏子，爵命古諸侯。", "老樹護靈鎮，神鴉迎客舟。", "晨昏兩潮汐，尸祝幾春秋。", "參佐憑風景，輕囂走不休。"]'),
('b10674ef-632c-4b22-9820-e8263c6008e4','龍湖觀人釣魚','丘葵','宋','宋诗','song-poetry','','[]','野客雙蓬鬢，溪童一釣竿。',48,'全唐诗/poet.song.244000.json','["野客雙蓬鬢，溪童一釣竿。", "得魚何與我，對境自成歡。", "日暮欲歸去，支筇更一看。", "淡紅千草燭，濃綠萬花盤。"]'),
('c3caf45e-a549-48f2-9416-5810d0569197','遊承天寺海翁首座相與登月臺因過方丈','丘葵','宋','宋诗','song-poetry','','[]','偶趁秋風一到城，市塵湫隘敗人清。',64,'全唐诗/poet.song.244000.json','["偶趁秋風一到城，市塵湫隘敗人清。", "牽絲聊作逢場戲，舉眼那知得月明。", "寂外幡幢皆古意，堂邊萱草自秋聲。", "因過方寸觀心印，見得泥牛入海行。"]');
